(function(w){w.__PC_DUOC_CHUNKS=w.__PC_DUOC_CHUNKS||{};w.__PC_DUOC_CHUNKS["jci-03"]=[{"c":"COP.01.02","ch":"COP","t":"Việc cung cấp các dịch vụ có rủi ro cao được hướng dẫn bởi các hướng dẫn thực hành chuyên môn, luật pháp và quy định.","p":"Cung cấp các dịch vụ có nguy cơ cao liên quan đến các rủi ro riêng biệt đối với bệnh nhân và nhân viên; bệnh viện\nthiết lập và thực hiện các hướng dẫn và quy trình để xác định và giảm thiểu các rủi ro liên quan đến các dịch vụ\nnày. Một số dịch vụ được coi là có nguy cơ cao do thiết bị y tế phức tạp, bản chất của phương pháp điều trị, khả\nnăng gây hại cho bệnh nhân hoặc tác dụng độc hại của một số loại thuốc có nguy cơ cao.\n\nChăm sóc rủi ro cao được hỗ trợ bằng cách sử dụng các công cụ như sau:\n• Hướng dẫn thực hành lâm sàng\n• Chính sách và thủ tục của bệnh viện\n• Con đường lâm sàng\n\nCác công cụ này rất quan trọng để nhân viên hiểu và thực hiện theo cách thống nhất. Lãnh đạo bệnh viện\nchịu trách nhiệm về những điều sau:\n\n(C P)\n\n•\nXác định các dịch vụ được coi là có nguy cơ cao trong bệnh viện\n•\nSử dụng quy trình hợp tác để phát triển các công cụ viết hướng dẫn chăm sóc đồng phục\n•\nĐào tạo nhân viên triển khai các công cụ này\n\nCác công cụ chăm sóc bằng văn bản phải được điều chỉnh theo dịch vụ có rủi ro cao để có hiệu quả trong\nviệc giảm thiểu rủi ro. Khi cung cấp các dịch vụ có rủi ro cao, bệnh viện thiết lập và triển khai các hướng\ndẫn và quy trình giải quyết các vấn đề sau:\n•\nCách lập kế hoạch chăm sóc, bao gồm các cân nhắc đặc biệt liên quan đến dịch vụ có rủi ro cao\n•\nTài liệu cần thiết để giao tiếp hiệu quả giữa nhóm chăm sóc\n•\nCác cân nhắc về sự đồng ý đặc biệt, nếu phù hợp\n•\nCác yêu cầu theo dõi bệnh nhân, bao gồm việc sử dụng đúng cách các báo động\n•\nCác trình độ hoặc kỹ năng đặc biệt của nhân viên tham gia vào quy trình chăm sóc\n•\nTính khả dụng và việc sử dụng các thiết bị y tế chuyên dụng\n\nCác nhà lãnh đạo bệnh viện xác định thêm rủi ro đối với các tình trạng mắc phải trong bệnh viện do bất\nkỳ quy trình hoặc kế hoạch chăm sóc nào gây ra. Ví dụ về các tình trạng mắc phải trong bệnh viện bao gồm:\n•\nHuyết khối tĩnh mạch sâu, loét do tì đè và nhiễm trùng liên quan đến máy thở ở những bệnh nhân\nđang được hỗ trợ sự sống\n•\nTổn thương thần kinh và tuần hoàn ở những bệnh nhân bị hạn chế\n•\nTiếp xúc với mầm bệnh qua đường máu ở những bệnh nhân chạy thận nhân tạo\n•\nNhiễm trùng đường truyền trung tâm\n•\nNgã\n\nKhi những rủi ro này xuất hiện, chúng phải được ngăn ngừa bằng cách giáo dục nhân viên và xây dựng các\nchính sách, hướng dẫn và quy trình phù hợp. Bệnh viện sử dụng thông tin đo lường để đánh giá các dịch\nvụ được cung cấp và tích hợp thông tin đó vào chương trình cải thiện chất lượng chung của bệnh viện.","m":[{"t":"Lãnh đạo bệnh viện xác định, bằng văn bản, các dịch vụ có rủi ro cao, bao gồm ít nhất các dịch vụ sau đây khi bệnh viện cung cấp:","b":["Dịch vụ cấp cứu","Hỗ trợ sự sống, bao gồm máy thở và oxy hóa màng ngoài cơ thể","Dịch vụ bệnh truyền nhiễm","Thẩm phân","Hạn chế","Hóa trị","Dịch vụ chăm sóc đặc biệt"]},{"t":"Lãnh đạo bệnh viện thiết lập và thực hiện các chính sách, quy trình và/hoặc nguyên tắc chăm sóc bằng văn bản cho các dịch vụ có rủi ro cao do bệnh viện cung cấp.","b":[]},{"t":"Nhân viên được đào tạo để sử dụng các công cụ bằng văn bản cho các dịch vụ có rủi ro cao.","b":[]},{"t":"Lãnh đạo bệnh viện xác định các rủi ro bổ sung có thể ảnh hưởng đến các dịch vụ có rủi ro cao và thực hiện các biện pháp để giảm và/hoặc ngăn ngừa các rủi ro này.","b":[]},{"t":"Các tình trạng mắc phải tại bệnh viện được theo dõi và đưa vào chương trình cải thiện chất lượng của bệnh viện. Quản lý hệ thống báo động lâm sàng","b":[]}],"sec":"Cung cấp dịch vụ chăm sóc cho tất cả bệnh nhân"},{"c":"COP.02.00","ch":"COP","t":"Bệnh viện thực hiện các chính sách và quy trình đảm bảo an toàn cho hệ thống báo động lâm sàng.","p":"Hệ thống báo động lâm sàng có mục đích cảnh báo người chăm sóc về các vấn đề tiềm ẩn của bệnh nhân hoặc sự\ncố thiết bị. Tuy nhiên, hệ thống báo động lâm sàng không được quản lý đúng cách sẽ gây nguy hiểm cho sự an\ntoàn của bệnh nhân. Các yếu tố rủi ro liên quan đến quản lý báo động bao gồm quá nhiều thiết bị có báo động,\ncài đặt mặc định không ở mức có thể thực hiện được và giới hạn báo động quá hẹp hoặc không phù hợp với\ntình trạng của bệnh nhân. Khu vực chăm sóc bệnh nhân có nhiều tín hiệu báo động và tiếng ồn từ các báo động\nkhông được quản lý đúng cách khiến nhân viên mất cảnh giác và khiến họ bỏ lỡ, phớt lờ hoặc tắt báo động.\nNhững vấn đề này rất khác nhau giữa các bệnh viện và trong các khu vực lâm sàng khác nhau trong một bệnh\nviện. Lãnh đạo bệnh viện phải xây dựng một phương pháp tiếp cận có hệ thống, phối hợp để giảm thiểu rủi ro\nliên quan đến quản lý báo động lâm sàng.\n\nViệc chuẩn hóa góp phần quản lý hệ thống báo động an toàn, nhưng các giải pháp quản lý báo động có thể phải\nđược thiết kế cho các đơn vị lâm sàng, nhóm bệnh nhân hoặc từng bệnh nhân cụ thể. Khi thiết kế các giải pháp\ntùy chỉnh để quản lý báo động phù hợp, lãnh đạo bắt đầu bằng cách xác định các tín hiệu báo động quan trọng\nnhất cần quản lý. Ví dụ, báo động phổ biến nhất cần giải quyết trong nhóm bệnh nhân tim mạch trưởng thành\nsẽ là theo dõi tim và trong quá trình chuyển dạ và sinh nở, báo động theo dõi thai nhi có thể là phổ biến nhất.\n\nViệc cân nhắc những điều sau đây có thể hữu ích trong việc xác định các tín hiệu báo động có thể gây nguy cơ\ncho sự an toàn của bệnh nhân:\n• Đầu vào từ nhân viên lâm sàng\n• Dữ liệu từ các thiết bị y tế, bao gồm cả báo động sai hoặc không thể thực hiện được\n• Rủi ro cho bệnh nhân nếu tín hiệu báo động không được xử lý hoặc nếu nó hoạt động không bình thường\n• Có cần các tín hiệu báo động cụ thể hay không hoặc góp phần không cần thiết vào tiếng ồn báo động và tình\ntrạng báo động mệt mỏi\n• Khả năng gây hại cho bệnh nhân dựa trên lịch sử sự cố nội bộ\n• Các hướng dẫn và thông lệ tốt nhất đã được công bố","m":[{"t":"Lãnh đạo bệnh viện triển khai chương trình quản lý bằng văn bản đối với các tín hiệu báo động gây nguy cơ cho sự an toàn của bệnh nhân.","b":[]},{"t":"Chương trình xác định các tín hiệu báo động quan trọng nhất cần được quản lý dựa trên rủi ro đối với sự an toàn của bệnh nhân.","b":[]},{"t":"Lãnh đạo bệnh viện xây dựng và triển khai các chiến lược để quản lý báo động bao gồm:","b":["Cài đặt phù hợp về mặt lâm sàng cho các tín hiệu báo động","Các tình huống có thể vô hiệu hóa các tín hiệu báo động","Các trường hợp phải xem xét và/hoặc thay đổi các thông số báo động (ví dụ,","khi tình trạng bệnh nhân có những thay đổi đáng kể, khi bệnh nhân được chuyển đến các cấp độchăm sóc khác nhau)","Xác định những người có thẩm quyền thiết lập các thông số báo động","Chỉ định những người có thẩm quyền thay đổi các thông số báo động","Giảm tiếng ồn báo động không cần thiết và cải thiện tình trạng mệt mỏi do báo động trong đội ngũ nhân viên lâm sàng"]},{"t":"Đội ngũ nhân viên lâm sàng được đào tạo về mục đích và hoạt động của các hệ thống báo động mà họ chịu trách nhiệm.","b":[]},{"t":"Đội ngũ nhân viên chịu trách nhiệm quản lý các báo động lâm sàng được đào tạo và có đủ năng lực để thực hiện việc đó.","b":[]},{"t":"Hệ thống báo động, chính sách và quy trình, và quy trình đào tạo nhân viên được xem xét khi cần thiết và theo quy trình xem xét chính sách của bệnh viện, tối thiểu ba năm một lần, để xác định và thực hiện các cải tiến. (C P) Nhận biết những thay đổi về tình trạng bệnh nhân","b":[]}],"sec":"Quản lý hệ thống báo động lâm sàng"},{"c":"COP.03.00","ch":"COP","t":"Đội ngũ nhân viên lâm sàng được đào tạo để nhận biết và ứng phó với những thay đổi về tình trạng của bệnh nhân.","p":"Các bệnh viện áp dụng phương pháp tiếp cận có hệ thống để nhận biết sớm và phản ứng với những thay đổi\nvề tình trạng bệnh nhân sẽ giảm được tình trạng ngừng tim phổi và tử vong ở bệnh nhân. Điều cần thiết là\nphải nhận biết các dấu hiệu cho thấy tình trạng bệnh nhân thay đổi hoặc xấu đi. Thông thường, bệnh nhân\nsẽ biểu hiện các dấu hiệu cảnh báo sớm (ví dụ, các dấu hiệu sinh tồn xấu đi hoặc tình trạng thần kinh thay\nđổi nhẹ) ngay trước khi trải qua tình trạng suy giảm lâm sàng đáng kể, dẫn đến một sự kiện lớn. Đội ngũ\nnhân viên lâm sàng sử dụng các tiêu chí sinh lý để hỗ trợ phát hiện sớm những bệnh nhân đang xấu đi. Hầu\nhết những bệnh nhân bị ngừng tim phổi hoặc ngừng thở đều có tình trạng xấu đi về mặt lâm sàng trước khi\nngừng tim. Kết quả lâm sàng sẽ được cải thiện khi đội ngũ nhân viên có thể xác định sớm những bệnh nhân\nnày và yêu cầu hỗ trợ thêm từ những cá nhân được đào tạo đặc biệt.\nTất cả nhân viên lâm sàng phải được giáo dục và đào tạo để nhận biết và can thiệp khi bệnh nhân biểu hiện\ncác dấu hiệu sinh lý nằm ngoài phạm vi bình thường, cho thấy khả năng bệnh nhân xấu đi. Phản ứng sớm\nvới những thay đổi về tình trạng bệnh nhân là rất quan trọng để có khả năng ngăn ngừa tình trạng xấu đi\nthêm.\nKhông cứu chữa (FTR) là không hoặc chậm trễ trong việc nhận biết và phản ứng với bệnh nhân nằm viện\nđang gặp biến chứng do quá trình bệnh lý hoặc can thiệp y tế và là nguyên nhân tử vong được công nhận tại\nbệnh viện. Các biện pháp cứu hộ không thành công đã được xây dựng cho nhiều chuyên khoa khác nhau, bao\ngồm:\n• Dịch vụ phẫu thuật cho người lớn và trẻ em\n• Chăm sóc tim cho người lớn\n• Phẫu thuật chấn thương\n• Phẫu thuật tiêu hóa\nCác biện pháp cứu hộ không thành công được lựa chọn dựa trên nhóm dân số được điều trị và các dịch vụ\nđược cung cấp; dữ liệu từ các biện pháp này được sử dụng để xác định các cơ hội cải thiện quy trình.\nTiêu chí cảnh báo sớm, còn được gọi là điểm cảnh báo sớm, được sử dụng để nhanh chóng xác định tình\ntrạng bệnh nhân hoặc những thay đổi về tình trạng bệnh nhân. Các tiêu chí này dựa trên bằng chứng và theo\nđộ tuổi. Bệnh viện triển khai các tiêu chí cảnh báo sớm cho tất cả các nhóm tuổi mà bệnh viện chăm sóc. Các\nví dụ về tiêu chí cảnh báo sớm bao gồm:\n• Điểm cảnh báo sớm (EWS)\n• Điểm cảnh báo sớm đã sửa đổi (MEWS)\n• Điểm cảnh báo sớm cho trẻ sơ sinh (PEWS)\n• Điểm cảnh báo sớm cho trẻ sơ sinh (NEWS)\n• Điểm chấn thương đã sửa đổi (RTS)\n• Điểm 10 dấu hiệu của sự sống\n• Thang an thần do thuốc phiện gây ra ở Pasero (POSS)","m":[{"t":"Bệnh viện có quy trình có hệ thống để nhận biết và ứng phó với những thay đổi hoặc tình trạng xấu đi của bệnh nhân.","b":[]},{"t":"Bệnh viện thực hiện các tiêu chí cảnh báo sớm theo độ tuổi được ghi chép lại, mô tả các dấu hiệu sớm về sự thay đổi hoặc xấu đi trong tình trạng của bệnh nhân.","b":[]},{"t":"Bệnh viện có quy trình để nhân viên tìm kiếm sự hỗ trợ bổ sung khi họ lo ngại về tình trạng của bệnh nhân dựa trên tiêu chí cảnh báo sớm của bệnh viện.","b":[]},{"t":"Bệnh viện thông báo cho bệnh nhân và gia đình cách tìm kiếm sự hỗ trợ khi họ có lo ngại về tình trạng của bệnh nhân. (C P) Dịch vụ hồi sức","b":[]}],"sec":"Nhận biết những thay đổi về tình trạng bệnh nhân"},{"c":"COP.04.00","ch":"COP","t":"Dịch vụ hồi sức có sẵn trong toàn bệnh viện.","p":"Việc bắt đầu ngay lập tức các biện pháp ép tim, hỗ trợ hô hấp và khử rung tim khi được chỉ định sẽ ảnh hưởng đến kết quả\nđiều trị của bệnh nhân, bao gồm ngăn ngừa thương tích vĩnh viễn, tàn tật hoặc tử vong. Do đó, các dịch vụ hồi sức phải có sẵn\ntrong toàn bộ bệnh viện để giảm thời gian phản ứng và cải thiện kết quả điều trị của bệnh nhân.\n\nViệc hồi sức thành công cho bệnh nhân ngừng tim phổi phụ thuộc vào các biện pháp can thiệp quan trọng, chẳng hạn như\nkhử rung tim sớm và bắt đầu hỗ trợ sự sống nâng cao. Các dịch vụ này phải có sẵn cho tất cả bệnh nhân, 24\ngiờ một ngày, mọi ngày. Nhân viên được đào tạo về hồi sức phải có quyền truy cập vào thiết bị y tế tiêu chuẩn và\nthuốc để hồi sức.\n\nCần bắt đầu hỗ trợ sự sống cơ bản ngay khi phát hiện ngừng tim hoặc ngừng hô hấp và phải có quy trình để cung cấp hỗ trợ\nsự sống nâng cao trong vòng chưa đầy 5 phút. Mặc dù yêu cầu đối với COP.04.00, ME 3 là phản ứng dưới 5 phút, nhưng\nbệnh viện nên liên tục đánh giá lại thời gian phản ứng của mình và nỗ lực rút ngắn thời gian phản ứng càng nhiều càng tốt.\nĐiều này có thể bao gồm các yếu tố như\nvị trí đặt xe đẩy cấp cứu và thiết bị như máy khử rung tim ngoài tự động (AED) và phân công/vị trí của nhân viên ứng phó với\ncác trường hợp cấp cứu hồi sức.\n\nCác dịch vụ hồi sức, thiết bị và đào tạo nhân viên trong bệnh viện phải dựa trên bằng chứng lâm sàng và nhóm dân số được\nphục vụ (ví dụ, nếu bệnh viện có nhóm dân số nhi khoa, thiết bị y tế để hồi sức nhi khoa phải có sẵn). Bệnh viện thực hiện các\nđánh giá nội bộ về các tình huống khẩn cấp trước đây để đánh giá thời gian phản ứng và tính khả dụng của thiết bị phù hợp và\nxác định các lĩnh vực cần cải thiện.\n\nLưu ý: Tất cả các khu vực của bệnh viện bao gồm tất cả các khu vực cung cấp dịch vụ và điều trị, bao gồm các khu vực điều trị\nhoặc chẩn đoán trong các tòa nhà riêng biệt trong khuôn viên bệnh viện. Bệnh viện xác định dịch vụ hồi sức, thiết bị và đào tạo\nnào được cung cấp dựa trên nhóm dân số bệnh nhân của mình. Các nguồn lực này phải có sẵn ngay lập tức tại tất cả các khu\nvực mà nhóm dân số bệnh nhân cụ thể nhận được dịch vụ. Ví dụ, các bệnh viện điều trị trẻ em phải có đội ngũ nhân viên lâm\nsàng được đào tạo về hỗ trợ sự sống nâng cao cho nhi khoa, có thiết bị và thuốc nhi khoa được chuẩn hóa và có thể lựa chọn\nkích thước hoặc liều lượng thuốc phù hợp dựa trên cân nặng hoặc kích thước của trẻ.\n\nThiết bị và thuốc hồi sức được chuẩn hóa trong toàn bộ bệnh viện. Lãnh đạo bệnh viện và nhân viên lâm sàng xác định cách\nlưu trữ và chuẩn hóa thiết bị tùy thuộc vào nhóm bệnh nhân được phục vụ, như trong các ví dụ sau:\n• Các khoa cấp cứu điều trị cho người lớn và trẻ em có thể có hai xe hồi sức riêng biệt—một cho người lớn và một cho trẻ\nem—hoặc một xe có ngăn kéo được chỉ định cho bệnh nhân người lớn và trẻ em.\n• Các khoa nhi có thể có xe hồi sức bao gồm thiết bị và thuốc theo cân nặng phù hợp cho bệnh nhân từ trẻ sơ sinh đến người\nlớn tuổi.\n• Các khoa sản có thể có đồ dùng hồi sức cho bệnh nhân chuyển dạ trong một hộp hồi sức và đồ dùng hồi sức cho trẻ sơ sinh\ntrong một hộp hồi sức riêng.\n\nHỗ trợ sự sống nâng cao được cung cấp trong vòng chưa đầy 5 phút. Kết quả của bệnh nhân phụ thuộc vào hồi sức tim phổi\n(CPR) chất lượng cao và nhận biết chính xác nguyên nhân và phương pháp điều trị cho tình trạng ngừng tim phổi. Do đó, sau\n5 phút, một số lượng nhân viên đủ được đào tạo về hỗ trợ sự sống nâng cao phải có mặt và bắt đầu các giao thức hỗ trợ sự\nsống nâng cao dựa trên tình trạng và dữ liệu lâm sàng của bệnh nhân. Đội ngũ nhân viên được đào tạo đầy đủ về hỗ trợ sự\nsống nâng cao phải luôn có mặt và sẵn sàng hỗ trợ các nỗ lực hồi sức cho đến khi sự kiện kết thúc.\n\n(C P)\n\nNếu bệnh viện liên tục khởi động hỗ trợ sự sống nâng cao trong vòng chưa đầy 5 phút, dữ liệu chất lượng\ncần được xem xét để xác định thời gian này có thể ngắn hơn nữa như thế nào. Một ủy ban liên ngành có thể\nđược thành lập để hoàn thành các đánh giá dịch vụ hồi sức. Các đánh giá này bao gồm các trường hợp hồi\nsức và dữ liệu để xác định và đề xuất các cải tiến về thực hành và hệ thống trong hiệu suất hồi sức.","m":[{"t":"Dịch vụ hồi sức có sẵn và được cung cấp cho tất cả bệnh nhân 24 giờ một ngày, mọi ngày, trên khắp các khu vực của bệnh viện.","b":[]},{"t":"Thiết bị y tế để hồi sức và thuốc men hỗ trợ sự sống cơ bản và nâng cao được chuẩn hóa và có sẵn để sử dụng dựa trên dân số được phục vụ. (Xem thêm MMU.03.01, ME 4)","b":[]},{"t":"Tại mọi khu vực của bệnh viện, hỗ trợ sự sống cơ bản được tiến hành ngay khi phát hiện tình trạng ngừng tim hoặc ngừng hô hấp, và hỗ trợ sự sống nâng cao được tiến hành trong vòng chưa đầy 5 phút.","b":[]},{"t":"Bệnh viện thực hiện đánh giá nội bộ về hiệu quả của tất cả các sự kiện hồi sức và nỗ lực cải thiện các lĩnh vực đã xác định cần cải thiện, bao gồm tối thiểu những nội dung sau:","b":["Tần suất các dấu hiệu cảnh báo sớm về tình trạng xấu đi về mặt lâm sàng xuất hiện trước khi ngừng tim trong bệnh viện ở những bệnh nhân trong các đơn vị chăm sóc không được theo dõi hoặc không quan trọng","Sự kịp thời trong phản ứng của nhân viên đối với tình trạng ngừng tim","Thời gian bắt đầu hỗ trợ tim mạch nâng cao (ACLS) trong thời gian ngắn nhất có thể","Chất lượng hồi sức tim phổi (CPR)","Quy trình chăm sóc sau khi ngừng tim","Kết quả sau khi ngừng tim Quản lý bệnh nhân có nguy cơ tự tử hoặc tự làm hại bản thân"]}],"sec":"Dịch vụ hồi sức"},{"c":"COP.05.00","ch":"COP","t":"Bệnh viện có quy trình xác định và bảo vệ bệnh nhân có nguy cơ tự tử và tự làm hại bản thân.","p":"Tự tử được coi là một sự kiện báo hiệu. Bệnh nhân được đánh giá hoặc điều trị các tình trạng sức khỏe hành vi\nthường có ý định tự tử. Bệnh viện phải thực hiện sàng lọc và đánh giá để xác định những bệnh nhân có nguy\ncơ tự tử và tự làm hại bản thân nhằm giảm thiểu khả năng tự tử hoặc tự làm hại bản thân.\n\nSàng lọc xác định những người có nguy cơ hoặc có khả năng cần được đánh giá chuyên sâu hơn. Đánh giá là\nmột quá trình có hệ thống được thực hiện để đánh giá các nhu cầu sau đó có thể được đáp ứng hoặc lập kế\nhoạch xung quanh họ về cách đáp ứng các nhu cầu đó, do đó, cá nhân tiến hành đánh giá phải có chuyên môn\nhoặc chuyên môn trong lĩnh vực được đánh giá.\n\nCác công cụ sàng lọc được xác thực là một cách hiệu quả để xác định những cá nhân cần được đánh giá thêm\nđể xác định nguy cơ tự tử. Một công cụ sàng lọc được xác thực là công cụ đã được thử nghiệm khoa học về độ\ntin cậy (khả năng của công cụ trong việc cung cấp kết quả nhất quán), tính hợp lệ (mức độ mà công cụ đo\nlường tình trạng mà nó được thiết kế để đo lường), độ nhạy (khả năng của công cụ trong việc xác định chính\nxác những cá nhân mắc tình trạng đó) và tính đặc hiệu (khả năng của công cụ trong việc xác định chính xác\nnhững cá nhân không mắc tình trạng đó). Ngoài ra, bệnh viện phải lựa chọn các công cụ sàng lọc đã được xác\nthực phù hợp với dân số (ví dụ: phù hợp với độ tuổi).\n\nKhi sử dụng các công cụ sàng lọc đã được xác thực, các tổ chức không nên thay đổi cách diễn đạt của các câu\nhỏi vì những thay đổi nhỏ có thể ảnh hưởng đến độ chính xác của các công cụ.\n\n(C P)\n\nĐiều quan trọng là các tổ chức phải đảm bảo rằng các công cụ sàng lọc đã chọn được triển khai và hoàn\nthành theo chỉ dẫn của người tạo ra các công cụ đó. Ví dụ, Thang đánh giá mức độ nghiêm trọng của hành vi\ntự tử Columbia (C-SSRS) là một công cụ sàng lọc đã được xác thực bao gồm sáu câu hỏi. Tùy thuộc vào câu\ntrả lời cho hai câu hỏi đầu tiên, các câu hỏi bổ sung sẽ được áp dụng. Một hoặc nhiều câu hỏi có thể bị bỏ sót\nnếu công cụ không được triển khai hoặc hoàn thành theo chỉ dẫn. Một ví dụ khác, Công cụ sàng lọc rủi ro tự\ntử Hỏi các câu hỏi sàng lọc tự tử (ASQ) là một công cụ sàng lọc đã được xác thực gồm bốn câu hỏi, cũng\nbao gồm một câu hỏi thứ năm để đánh giá mức độ nhạy bén. Câu hỏi này có thể bị bỏ sót nếu công cụ không\nđược triển khai hoặc hoàn thành theo chỉ dẫn. Do đó, nếu không hoàn thành theo hướng dẫn, tính hợp lệ của\ncông cụ để xác định những cá nhân có nguy cơ tự tử sẽ bị ảnh hưởng. Cuối cùng, mỗi tổ chức có trách nhiệm\nđảm bảo rằng các công cụ đã được xác thực được triển khai và hoàn thành chính xác.\n\nCác bệnh viện chăm sóc bệnh nhân có nguy cơ tự tử và tự làm hại bản thân cần đánh giá các rủi ro trong môi\ntrường vật lý để xác định các khu vực và đặc điểm có thể được sử dụng để cố gắng tự tử. Bệnh viện tâm thần\nvà bệnh viện có khoa và đơn vị tâm thần thiết kế, xây dựng và duy trì môi trường theo cách giảm thiểu hoặc\nloại bỏ các rủi ro được xác định trong đánh giá rủi ro môi trường. Các đơn vị không phải khoa tâm thần\ntrong bệnh viện đánh giá các khu vực lâm sàng để xác định các vật thể có thể được sử dụng để tự gây thương\ntích để có thể loại bỏ chúng hoặc giảm thiểu rủi ro do các vật phẩm đó gây ra khi cần thiết, khỏi khu vực\nxung quanh bệnh nhân được xác định là có nguy cơ tự tử cao (ví dụ, tại bệnh viện tâm thần, bảo vệ các cửa\nsổ có thể mở được và loại bỏ các điểm neo, bản lề cửa và móc có thể được sử dụng để treo; tại bệnh viện\nkhông phải khoa tâm thần, loại bỏ các vật dụng như vòng đo huyết áp, dây điện thoại, dây đèn gọi và dây\ntheo dõi khi không cần thiết cho việc chăm sóc lâm sàng của bệnh nhân). Ngoài ra, bệnh viện nên có quy\ntrình xử lý quần áo và đồ đạc của bệnh nhân để giảm thiểu rủi ro, chẳng hạn như tháo và buộc chặt giày có\ndây giày và các vật dụng khác của bệnh nhân có thể được sử dụng để tự gây thương tích. Quy trình đánh giá\nrủi ro môi trường của bệnh viện nên là điểm khởi đầu và cũng nên bao gồm một kế hoạch giảm thiểu rủi ro\nnhư quan sát một kèm một khi có chỉ định.","m":[{"t":"Bệnh viện tiến hành đánh giá rủi ro môi trường để xác định các đặc điểm trong môi trường vật lý có thể được sử dụng để cố gắng tự tử hoặc tự làm hại bản thân; bệnh viện thực hiện hành động cần thiết để giảm thiểu rủi ro. (Xem thêm FMS.03.00, ME 1; FMS.04.00, ME 2)","b":[]},{"t":"Sử dụng một công cụ sàng lọc đã được xác thực, bệnh viện sàng lọc tất cả bệnh nhân có ý định tự tử đang được đánh giá hoặc điều trị các tình trạng hành vi là lý do chính khiến họ cần được chăm sóc.","b":[]},{"t":"Bệnh viện sử dụng quy trình dựa trên bằng chứng để tiến hành đánh giá tự tử đối với những bệnh nhân có kết quả sàng lọc dương tính với ý định tự tử. Đánh giá trực tiếp hỏi về ý định tự tử, kế hoạch, ý định, hành vi tự tử hoặc tự làm hại bản thân, các yếu tố rủi ro và các yếu tố bảo vệ.","b":[]},{"t":"Việc sàng lọc và đánh giá tự tử được ghi lại trong hồ sơ y tế của bệnh nhân hoặc theo luật pháp và quy định khi áp dụng.","b":[]},{"t":"Bệnh viện tuân thủ các chính sách và thủ tục bằng văn bản về việc chăm sóc bệnh nhân được xác định là có nguy cơ tự tử. Tối thiểu, các chính sách phải bao gồm những điều sau đây:","b":["Đào tạo và đánh giá năng lực của nhân viên chăm sóc bệnh nhân có nguy cơ tự tử","Hướng dẫn đánh giá lại bệnh nhân có nguy cơ tự tử và tự làm hại bản thân","Theo dõi những bệnh nhân có nguy cơ tự tử và tự làm hại bản thân cao"]},{"t":"Bệnh viện tuân thủ các chính sách và quy trình bằng văn bản về tư vấn và chăm sóc theo dõi khi xuất viện cho những bệnh nhân được xác định có nguy cơ tự tử và tự làm hại bản thân.","b":[]},{"t":"Bệnh viện giám sát việc thực hiện và hiệu quả của các chính sách và thủ tục sàng lọc, đánh giá và quản lý bệnh nhân có nguy cơ tự tử và tự gây thương tích, và thực hiện hành động khi cần thiết để cải thiện việc tuân thủ. (C P) Liệu pháp dinh dưỡng và thực phẩm","b":[]}],"sec":"Quản lý bệnh nhân có nguy cơ tự tử hoặc tự làm hại bản thân"},{"c":"COP.06.00","ch":"COP","t":"Thực phẩm, sản phẩm dinh dưỡng và liệu pháp dinh dưỡng có sẵn cho bệnh nhân.","p":"Thức ăn và dinh dưỡng phù hợp góp phần cải thiện kết quả điều trị cho bệnh nhân, bao gồm chữa lành vết\nthương và kiểm soát các bệnh và rối loạn phức tạp. Dựa trên nhu cầu, chẩn đoán và kế hoạch chăm sóc được\nđánh giá của bệnh nhân, bác sĩ hoặc người chăm sóc đủ điều kiện khác sẽ chỉ định thức ăn hoặc các chất dinh\ndưỡng khác cho bệnh nhân. Chỉ định có thể bao gồm các yêu cầu chế độ ăn uống đặc biệt như chế độ ăn ít\ncholesterol, chế độ ăn cho bệnh nhân tiểu đường hoặc chất lỏng trong suốt.\nBệnh nhân tham gia lập kế hoạch và lựa chọn thực phẩm bất cứ khi nào có thể. Bệnh nhân được cung cấp nhiều\nlựa chọn thực phẩm phù hợp với tình trạng dinh dưỡng của họ khi có thể. Gia đình bệnh nhân có thể tham gia\ncung cấp thực phẩm phù hợp với văn hóa, tôn giáo và các truyền thống và tập quán khác và phù hợp với chẩn\nđoán của bệnh nhân khi phù hợp. Khi gia đình bệnh nhân hoặc những người khác cung cấp thực phẩm cho bệnh\nnhân, họ được giáo dục về các loại thực phẩm chống chỉ định với nhu cầu và kế hoạch chăm sóc của bệnh nhân,\nbao gồm thông tin về bất kỳ loại thuốc nào liên quan đến tương tác thực phẩm. Thực phẩm do gia đình hoặc\nnhững người khác cung cấp được bảo quản trong điều kiện thích hợp, tuân theo các hướng dẫn bảo quản thực\nphẩm hiện hành, để ngăn ngừa ô nhiễm.\nBệnh nhân được sàng lọc để xác định những người có thể có nguy cơ dinh dưỡng trong quá trình đánh giá ban\nđầu. Những bệnh nhân này được giới thiệu đến chuyên gia dinh dưỡng để đánh giá thêm. Một kế hoạch cho liệu\npháp dinh dưỡng được xây dựng và thực hiện cho những bệnh nhân có nguy cơ dinh dưỡng. Liệu pháp dinh\ndưỡng bao gồm những điều sau:\n• Nuôi ăn qua đường tiêu hóa\n• Dinh dưỡng hoàn toàn qua đường tĩnh mạch\n• Tăng cường sữa mẹ\n• Các chất bổ sung dinh dưỡng khác\nTiến trình của bệnh nhân được theo dõi và ghi lại trong hồ sơ y tế của họ. Bác sĩ, y tá, dịch vụ dinh dưỡng và,\nkhi thích hợp, gia đình bệnh nhân hợp tác để lập kế hoạch và cung cấp liệu pháp dinh dưỡng.","m":[{"t":"Thường xuyên có nhiều lựa chọn thực phẩm hoặc dinh dưỡng, phù hợp với tình trạng, chế độ chăm sóc và nhu cầu của bệnh nhân.","b":[]},{"t":"Có đơn đặt hàng thực phẩm trong hồ sơ y tế của bệnh nhân dựa trên tình trạng dinh dưỡng và nhu cầu của bệnh nhân trước khi bệnh nhân nội trú được cho ăn.","b":[]},{"t":"Việc phân phối thực phẩm được thực hiện kịp thời và các yêu cầu đặc biệt được đáp ứng.","b":[]},{"t":"Khi gia đình cung cấp thực phẩm, họ được giáo dục về những hạn chế trong chế độ ăn uống của bệnh nhân.","b":[]},{"t":"Thực phẩm và các sản phẩm dinh dưỡng, bao gồm cả những sản phẩm do gia đình cung cấp, được bảo quản trong điều kiện thích hợp, tuân thủ các hướng dẫn bảo quản thực phẩm hiện hành, để ngăn ngừa ô nhiễm.","b":[]},{"t":"Bệnh nhân được xác định có nguy cơ dinh dưỡng sẽ được điều trị dinh dưỡng.","b":[]},{"t":"Một quy trình hợp tác được sử dụng để lập kế hoạch, cung cấp và theo dõi liệu pháp dinh dưỡng.","b":[]},{"t":"Phản ứng của bệnh nhân đối với liệu pháp dinh dưỡng được theo dõi và ghi lại trong hồ sơ y tế.","b":[]}],"sec":"Liệu pháp dinh dưỡng và thực phẩm"},{"c":"COP.07.00","ch":"COP","t":"Cơn đau được kiểm soát hiệu quả.","p":"Đau không thuyên giảm có tác động tiêu cực về mặt thể chất và tâm lý, và bệnh nhân bị đau có quyền được đánh giá và quản\nlý cơn đau phù hợp. Đau có thể là một phần trong trải nghiệm của bệnh nhân và có thể liên quan đến tình trạng hoặc bệnh\ntật của bệnh nhân. Đau cũng có thể là một phần dự kiến của một số phương pháp điều trị, thủ thuật hoặc xét nghiệm. Bệnh\nnhân được thông báo về khả năng đau khi đó là tác dụng dự kiến từ các phương pháp điều trị, thủ thuật hoặc xét nghiệm và\ncác lựa chọn nào để quản lý cơn đau có sẵn.\n\nDựa trên phạm vi dịch vụ được cung cấp, bệnh viện có các quy trình để quản lý cơn đau phù hợp, bao gồm:\n• Xác định bệnh nhân bị đau trong quá trình đánh giá ban đầu và đánh giá lại\n• Cung cấp thông tin cho bệnh nhân về cơn đau có thể là kết quả dự kiến của các phương pháp điều trị,\nquy trình hoặc kiểm tra\n• Quản lý cơn đau, bất kể nguồn gốc cơn đau, theo các hướng dẫn hoặc giao thức\nvà phù hợp với mục tiêu quản lý cơn đau của bệnh nhân\n• Giao tiếp và giáo dục bệnh nhân và gia đình về việc quản lý cơn đau và triệu chứng trong\nbối cảnh tín ngưỡng cá nhân, văn hóa và tôn giáo của họ\n• Giáo dục nhân viên lâm sàng về đánh giá và quản lý cơn đau","m":[{"t":"Bệnh nhân được thông báo về khả năng đau và các lựa chọn để kiểm soát cơn đau khi cơn đau là kết quả dự kiến của các phương pháp điều trị, thủ thuật hoặc xét nghiệm đã lên kế hoạch. (Xem thêm AOP.01.04, ME 3)","b":[]},{"t":"Bệnh nhân bị đau được chăm sóc theo hướng dẫn kiểm soát cơn đau và phù hợp với mục tiêu kiểm soát cơn đau của bệnh nhân.","b":[]},{"t":"Bệnh viện có các quy trình để giao tiếp và giáo dục bệnh nhân và gia đình về cơn đau. (Xem thêm ACC.01.04, ME 3)","b":[]},{"t":"Bệnh viện cung cấp giáo dục cho nhân viên lâm sàng về đánh giá và quản lý cơn đau. Chăm sóc cuối đời","b":[]}],"sec":"Quản lý cơn đau"},{"c":"COP.08.00","ch":"COP","t":"Bệnh viện có quy trình cung cấp dịch vụ chăm sóc cuối đời đáp ứng nhu cầu của bệnh nhân và gia đình, đồng thời tối ưu hóa sự thoải mái và phẩm giá của bệnh nhân.","p":"Bệnh nhân cuối đời hoặc sắp chết có những nhu cầu riêng; bệnh viện triển khai các quy trình để giải quyết\nnhững nhu cầu này và kết hợp sở thích của bệnh nhân và gia đình vào các quy trình chăm sóc. Chăm sóc\ncuối đời có thể bị ảnh hưởng bởi các truyền thống văn hóa và tôn giáo. Mối quan tâm đến sự thoải mái và\nphẩm giá của bệnh nhân hướng dẫn mọi khía cạnh chăm sóc trong giai đoạn cuối đời. Tất cả các nhân viên\nđều được thông báo về nhu cầu của bệnh nhân khi cuối đời. Những nhu cầu này bao gồm nhưng không\ngiới hạn ở những nhu cầu sau:\n• Điều trị các triệu chứng chính và thứ phát\n• Quản lý cơn đau và sự khó chịu\n• Phản hồi các mối quan tâm về tâm lý, xã hội, cảm xúc, tôn giáo và văn hóa của bệnh nhân và gia đình\n• Sự tham gia vào các quyết định chăm sóc\n\nĐánh giá bệnh nhân có thể xác định các triệu chứng cần được kiểm soát, chẳng hạn như buồn nôn, khó thở\nvà đau; các yếu tố làm giảm hoặc làm trầm trọng thêm các triệu chứng về thể chất; và phản ứng của bệnh\nnhân đối với việc kiểm soát triệu chứng. Xác định nhu cầu về thể chất của bệnh nhân chỉ là một khía cạnh\nđể xác định việc chăm sóc cuối đời của bệnh nhân. Bệnh nhân và gia đình cũng có thể cần các dịch vụ hỗ trợ\nvề mặt tinh thần, tâm lý xã hội và tâm linh, phù hợp với nhu cầu cá nhân và sở thích văn hóa của bệnh\nnhân.\n\n(C P)\n\nChăm sóc bệnh nhân (COP)\nChăm sóc cuối đời do bệnh viện cung cấp bao gồm nhưng không giới hạn ở những điều sau:\n•\nThực hiện các biện pháp can thiệp để kiểm soát cơn đau và sự khó chịu\n•\nCung cấp phương pháp điều trị phù hợp cho bất kỳ triệu chứng nào theo mong muốn của bệnh nhân\nvà gia đình\n•\nGiải quyết một cách nhạy cảm các vấn đề như khám nghiệm tử thi và hiến tặng nội tạng\n•\nTôn trọng các giá trị, tôn giáo và sở thích văn hóa của bệnh nhân\n•\nThu hút bệnh nhân và gia đình tham gia vào mọi khía cạnh chăm sóc\n•\nĐáp ứng các mối quan tâm về tâm lý, tình cảm, tinh thần và văn hóa của bệnh nhân và gia đình\n\nĐể đạt được các mục tiêu này, tất cả nhân viên phải được đào tạo và giáo dục để đánh giá và quản lý các nhu\ncầu của bệnh nhân và gia đình họ vào giai đoạn cuối đời. Mục tiêu của bệnh viện trong việc cung cấp dịch vụ\nchăm sóc vào giai đoạn cuối đời xem xét các bối cảnh cung cấp dịch vụ chăm sóc hoặc dịch vụ (chẳng hạn\nnhư bệnh viện dưỡng lão hoặc đơn vị chăm sóc giảm nhẹ), loại dịch vụ được cung cấp và nhóm bệnh nhân\nđược phục vụ. Bệnh viện xây dựng các quy trình để quản lý dịch vụ chăm sóc cuối đời, bao gồm việc sử\ndụng các công cụ đánh giá được công nhận như Thang đánh giá hiệu suất giảm nhẹ hoặc các công cụ khác\nkhi thích hợp. Các quy trình này bao gồm những nội dung sau:\n•\nĐánh giá và quản lý các triệu chứng\n•\nXác định tần suất đánh giá\n•\nĐiều trị bệnh nhân giai đoạn cuối một cách tôn trọng và có phẩm giá\n•\nLên kế hoạch cho các biện pháp phòng ngừa và điều trị để quản lý các triệu chứng\n•\nGiáo dục bệnh nhân, gia đình và nhân viên về cách quản lý các triệu chứng\n•\nHỗ trợ gia đình và/hoặc người chăm sóc bệnh nhân\n•\nHỗ trợ các thành viên nhân viên chăm sóc bệnh nhân hấp hối","m":[{"t":"Bệnh viện có quy trình đánh giá và quản lý nhu cầu của bệnh nhân đang được chăm sóc cuối đời.","b":[]},{"t":"Nhân viên được đào tạo và giáo dục về việc đánh giá và quản lý nhu cầu của bệnh nhân và gia đình họ vào cuối đời.","b":[]},{"t":"Bệnh viện cung cấp dịch vụ chăm sóc và hỗ trợ bệnh nhân phù hợp với bệnh nhân và gia đình họ có cân nhắc đến sở thích cá nhân, tâm linh/tôn giáo và văn hóa của họ.","b":[]},{"t":"Chăm sóc cuối đời giải quyết các triệu chứng, tình trạng và nhu cầu chăm sóc sức khỏe của bệnh nhân sắp chết như được chỉ ra trong đánh giá của họ, bao gồm nhu cầu về đau đớn và thoải mái.","b":[]},{"t":"Bệnh nhân và gia đình tham gia vào các quyết định chăm sóc cuối đời.","b":[]},{"t":"Bệnh viện cung cấp hỗ trợ cho gia đình bệnh nhân, người chăm sóc và nhân viên chăm sóc bệnh nhân đang hấp hối. Lưu ý: Các tiêu chuẩn sau đây được dùng trong các trường hợp bệnh nhân yêu cầu thông tin về hiến tặng nội tạng và mô và/hoặc khi có thể hiến tặng nội tạng hoặc mô. Khi thực hiện hiến tặng và cấy ghép nội tạng hoặc mô, các tiêu chuẩn cho các chương trình cấy ghép nội tạng và mô sẽ được áp dụng. Người ta nhận thấy rằng có sự khác biệt đáng kể giữa cấy ghép nội tạng và mô. Các yêu cầu áp dụng cho cả hai, tùy thuộc vào các dịch vụ mà bệnh viện cung cấp. Ví dụ, nếu bệnh viện chỉ thực hiện các dịch vụ cấy ghép mô, thì các yêu cầu sẽ áp dụng cho các dịch vụ cấy ghép mô do bệnh viện cung cấp. Các sản phẩm sau đây được coi là mô và tế bào theo các tiêu chuẩn bên dưới. Ví dụ về các sản phẩm mô và tế bào","b":["Màng ối/màng ối","Động mạch","Tế bào tự thân","Mô tự thân","Xương (C P)","Tủy xương","Bột xương","Bột xương","Bột xương","Mảnh xương xốp","Van tim (tim) (động mạch chủ, phổi)","Sụn","Tế bào sụn","Giác mạc"]}],"sec":"Chăm sóc cuối đời"},{"c":"COP.09.00","ch":"COP","t":"Bệnh viện thông báo cho bệnh nhân và gia đình về cách hiến tặng nội tạng và các mô khác.","p":"Bệnh nhân và gia đình nhận được thông tin về quy trình hiến tặng và cách thức tổ chức thu thập nội tạng cho cộng\nđồng, khu vực hoặc quốc gia (chẳng hạn như cơ quan hoặc mạng lưới thu thập nội tạng quốc gia hoặc khu vực) để\nđảm bảo an toàn cho người hiến tặng và người nhận nội tạng. Nhiều quốc gia đã xây dựng các quy trình và hệ\nthống để tăng nguồn cung cấp nội tạng có sẵn để ghép tạng. Ở một số quốc gia, luật pháp quy định rằng mọi người\nđều là người hiến tặng trừ khi có quy định khác. Điều này được coi là sự đồng ý được cho là có. Các quốc gia khác\nyêu cầu phải có sự đồng ý rõ ràng đối với việc hiến tặng nội tạng.\n\nBệnh viện có trách nhiệm xác định quy trình lấy và ghi lại sự đồng ý hiến tặng tế bào, mô và nội tạng theo các tiêu\nchuẩn đạo đức quốc tế và cách thức tổ chức thu thập nội tạng tại quốc gia của bệnh viện. Bệnh viện có trách nhiệm\nđảm bảo có các biện pháp kiểm soát đầy đủ để ngăn chặn bệnh nhân cảm thấy bị ép buộc phải hiến tặng.\n\nBệnh viện hỗ trợ sự lựa chọn của bệnh nhân và gia đình hiến tặng nội tạng và các mô khác để nghiên cứu hoặc ghép\ntạng. Bệnh nhân và gia đình được cung cấp thông tin về quy trình hiến tặng và cách thức tổ chức thu thập nội tạng\ncho cộng đồng, khu vực hoặc quốc gia.","m":[{"t":"Bệnh viện hỗ trợ bệnh nhân và gia đình lựa chọn hiến tặng nội tạng và các mô khác.","b":[]},{"t":"Bệnh viện cung cấp thông tin cho bệnh nhân và gia đình về quy trình hiến tặng.","b":[]},{"t":"Bệnh viện cung cấp thông tin cho bệnh nhân và gia đình về cách thức tổ chức thu thập nội tạng.","b":[]},{"t":"Bệnh viện đảm bảo có các biện pháp kiểm soát đầy đủ để ngăn ngừa bệnh nhân cảm thấy bị ép buộc phải hiến tặng.","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"COP.09.01","ch":"COP","t":"Bệnh viện cung cấp sự giám sát cho quá trình thu thập nội tạng và mô.","p":"Cần phải giám sát quá trình thu thập nội tạng và mô để đảm bảo rằng nó phù hợp với luật pháp và quy\nđịnh, tôn trọng các giá trị tôn giáo và văn hóa của cộng đồng và có đạo đức. Một trong những mục tiêu\nchính của việc giám sát quy trình mua sắm nội tạng và mô là thiết lập các yêu cầu về sự đồng ý.\n\n(C P)\n\nNhân viên bệnh viện được đào tạo về quy trình hiến tặng và hỗ trợ bệnh nhân và gia đình lựa chọn về\nviệc hiến tặng nội tạng và mô. Nhân viên cũng được đào tạo về các mối quan tâm và vấn đề đương đại\nliên quan đến hiến tặng nội tạng và tính khả dụng của các ca ghép tạng. Bệnh viện hợp tác với các bệnh\nviện và cơ quan khác trong cộng đồng chịu trách nhiệm về toàn bộ hoặc một phần của quy trình mua\nsắm, ngân hàng, vận chuyển hoặc ghép tạng.","m":[{"t":"Bệnh viện xây dựng một quy trình hiến tặng và mua sắm nội tạng và mô bằng văn bản phù hợp với luật pháp và quy định của khu vực cũng như các giá trị tôn giáo và văn hóa của khu vực đó.","b":[]},{"t":"Bệnh viện xác định các yêu cầu đồng ý đối với việc hiến tặng và mua sắm nội tạng và mô và xây dựng một quy trình đồng ý phù hợp với các yêu cầu đó.","b":[]},{"t":"Nhân viên được đào tạo về các vấn đề và mối quan tâm liên quan đến việc hiến tặng nội tạng và mua sắm mô cũng như tính khả dụng của các ca ghép tạng.","b":[]},{"t":"Bệnh viện hợp tác với các bệnh viện và cơ quan có liên quan trong cộng đồng để tôn trọng và thực hiện các lựa chọn hiến tặng.","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"COP.09.02","ch":"COP","t":"Các nhà lãnh đạo bệnh viện cung cấp nguồn lực để hỗ trợ chương trình ghép tạng, mô và/hoặc tế bào.","p":"Chương trình cấy ghép yêu cầu nhân viên có trình độ học vấn, đào tạo và nguồn lực chuyên biệt để cung cấp dịch\nvụ chăm sóc an toàn, chất lượng cao. Đào tạo và giáo dục nhân viên phải cụ thể đối với trách nhiệm và yêu cầu của\nca cấy ghép do bệnh viện cung cấp. Các nguồn lực thiết yếu khác bao gồm vật tư; phòng bệnh nhân có thông gió\ncần thiết cho loại thủ thuật cấy ghép (ví dụ, thông gió áp lực dương); dược phẩm cần thiết cho loại thủ thuật cấy\nghép; xét nghiệm trong phòng thí nghiệm để đảm bảo rằng các mô, cơ quan và tế bào không bị nhiễm bẩn; và các\nnguồn lực khác do người đứng đầu dịch vụ chương trình xác định. Các nguồn lực liên quan đến hệ thống quản lý\nthông tin là cần thiết để giúp thu thập dữ liệu liên quan đến rủi ro, kết quả và thông tin khác hỗ trợ chất lượng của\nchương trình cấy ghép.","m":[{"t":"Giáo dục và đào tạo nhân viên cụ thể cho các loại cơ quan, mô và/hoặc cấy ghép tế bào do bệnh viện cung cấp.","b":[]},{"t":"Lãnh đạo bệnh viện phân bổ nguồn lực cho chương trình cấy ghép.","b":[]},{"t":"Hệ thống quản lý thông tin được sử dụng để hỗ trợ chất lượng của chương trình cấy ghép.","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"COP.09.03","ch":"COP","t":"Bệnh viện xác định những người lãnh đạo chương trình cấy ghép đủ tiêu chuẩn và bao gồm một nhóm liên ngành bao gồm các nhân viên lâm sàng có chuyên môn về các chương trình cấy ghép có liên quan.","p":"Sự giám sát của một hoặc nhiều cá nhân đủ điều kiện và sự tham gia của một nhóm chăm sóc liên ngành\nđảm bảo chất lượng và sự an toàn của các dịch vụ cấy ghép và cải thiện thành công của ca cấy ghép và kết\nquả liên quan đến bệnh nhân.\n\nMột hoặc nhiều cá nhân đủ điều kiện phải chịu trách nhiệm hỗ trợ và giám sát tất cả các hoạt động của\nchương trình cấy ghép. Những cá nhân này có sự hỗ trợ và giám sát được xác định trong mô tả công việc\nvà đủ điều kiện để quản lý các dịch vụ cấy ghép thông qua giáo dục, đào tạo, kinh nghiệm, cấp phép\nvà/hoặc chứng nhận. Các bằng cấp bắt buộc phụ thuộc vào các hoạt động được thực hiện.\n\n(C P)\n\nNgười nhận ghép tạng và người hiến tạng sống có nhu cầu điều dưỡng, tâm lý, dược lý và dinh dưỡng cụ thể.\nLiên quan đến loại ghép tạng, một nhóm liên ngành bao gồm các cá nhân từ các chuyên ngành sau:\n• Y khoa\n• Điều dưỡng\n• Dinh dưỡng\n• Dược lý\n• Phòng ngừa và kiểm soát nhiễm trùng\n• Dịch vụ xã hội\n• Dịch vụ sinh sản\n• Dịch vụ tâm lý\n• Dịch vụ phục hồi chức năng\nNhóm này phải có trình độ, đào tạo và kinh nghiệm để cung cấp dịch vụ chăm sóc và dịch vụ cho người nhận\nghép tạng và người hiến tạng sống. Các bệnh viện có chương trình ghép tạng sẽ xem xét các loại cơ quan\nvà/hoặc mô được lấy và/hoặc ghép tạng khi thành lập nhóm ghép tạng liên ngành của mình. Các nhóm này\nđược thành lập với sự cân nhắc đến các rủi ro, thách thức, nhu cầu, luật pháp và quy định cụ thể cũng như\nhướng dẫn chuyên môn cho từng loại ghép tạng.","m":[{"t":"Chương trình ghép tạng có cơ sở hạ tầng, bao gồm các hệ thống và chính sách và quy trình bằng văn bản, có khả năng hỗ trợ mọi khía cạnh của chương trình.","b":[]},{"t":"Một cá nhân đủ tiêu chuẩn sẽ giám sát và quản lý chương trình ghép tạng.","b":[]},{"t":"Một cá nhân thực hiện trách nhiệm giám sát của chương trình theo quy định của chương trình ghép tạng.","b":[]},{"t":"Chương trình ghép tạng ghi lại thành phần của từng nhóm ghép tạng.","b":[]},{"t":"Chương trình ghép tạng ghi lại trách nhiệm của các thành viên trong nhóm.","b":[]},{"t":"Dựa trên các dịch vụ do nhóm ghép tạng cung cấp, nhóm bao gồm những cá nhân có kinh nghiệm về y khoa, điều dưỡng, dinh dưỡng, dược lý, phòng ngừa và kiểm soát nhiễm trùng, dịch vụ xã hội, dịch vụ tâm lý, dịch vụ phục hồi chức năng và điều phối ghép tạng.","b":[]},{"t":"Chương trình ghép tạng đánh giá trình độ, đào tạo và kinh nghiệm của các thành viên trong nhóm tại thời điểm mỗi cá nhân được cân nhắc cho nhóm ghép tạng.","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"COP.09.04","ch":"COP","t":"Có một cơ chế phối hợp được chỉ định cho tất cả các hoạt động cấy ghép.","p":"Một thành phần quan trọng trong việc đảm bảo chăm sóc an toàn, chất lượng cao trong suốt mọi giai đoạn\ncủa quá trình hiến tặng/người nhận là đảm bảo sự phối hợp và tính liên tục của việc chăm sóc người hiến\ntặng còn sống và người nhận ghép tạng. Các dịch vụ ghép tạng mang lại những rủi ro đặc biệt và quan\ntrọng đối với người nhận nội tạng, mô và tế bào và, trong trường hợp người hiến tặng còn sống,\nđối với người hiến tặng. Việc chăm sóc phức tạp mà người hiến tặng và người nhận cần đòi hỏi một cơ\nchế phối hợp, thường là một nhân viên lâm sàng có trình độ. Cá nhân này đảm bảo tính liên tục của việc\nchăm sóc cho người hiến tặng và/hoặc người nhận trong suốt quá trình ghép tạng. Cá nhân này cũng chịu\ntrách nhiệm trao đổi với nhóm chăm sóc về việc chăm sóc người hiến tặng và/hoặc người nhận. Điều này\ncó thể diễn ra thông qua các cuộc họp và tài liệu được tạo điều kiện thuận lợi.\n\nCá nhân chịu trách nhiệm phối hợp tất cả các hoạt động ghép tạng có thể là bác sĩ, y tá đã đăng ký hoặc\nnhân viên lâm sàng có trình độ khác—cá nhân này có thể được gọi là \"điều phối viên ghép tạng.”\n\n(C P)","m":[{"t":"The individual responsible for the coordination of the live donor’s and transplant recipient’s care is identified and available through all phases of transplant care.","b":[]},{"t":"facilitated through the pre-transplant, transplant, and discharge phases of transplantation.","b":[]},{"t":"phases of donation.","b":[]},{"t":"program activities.","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"COP.09.05","ch":"COP","t":"Bệnh viện thực hiện trách nhiệm ghép tạng, mô, tế bào.","p":"Các cơ quan, mô và tế bào là nguồn tài nguyên có hạn. Bệnh viện đảm bảo rằng các cơ quan, mô và tế bào được\nquản lý theo cách bảo vệ các nguồn tài nguyên này và đảm bảo tính toàn vẹn của chúng. Việc hiến tặng, mua sắm\nvà cấy ghép cơ quan, mô và tế bào được quản lý chặt chẽ. Bệnh viện tuân thủ mọi quy tắc và quy định do mạng\nlưới mua sắm và cấy ghép địa phương, khu vực hoặc quốc gia đặt ra. Các mạng lưới này thường yêu cầu nhiều\ndữ liệu khác nhau liên quan đến các dịch vụ cấy ghép để theo dõi chất lượng của các dịch vụ này và chỉ phân bổ\ncác cơ quan, mô và tế bào cho các bệnh viện có chương trình tuân thủ thành công.\n\nBệnh viện thực hiện các quy trình xử lý tất cả các cơ quan, mô và tế bào để đảm bảo xử lý an toàn và đảm bảo\nrằng bệnh nhân nhận được đúng cơ quan, mô hoặc tế bào trong tình trạng làm tăng khả năng cấy ghép thành\ncông. Các cơ quan, mô và tế bào có các yêu cầu cụ thể về\nvận chuyển và lưu trữ cho đến khi cấy ghép. Bệnh viện thực hiện đầy đủ các điều kiện này để duy trì khả năng\nsống của cơ quan, mô và tế bào. Ngoài ra, bệnh viện có một quy trình theo dõi các cơ quan, mô và tế bào được\ncấy ghép cho mục đích thu thập dữ liệu, bao gồm kết quả của ca cấy ghép và khả năng thu hồi bất kỳ ca cấy ghép\nnào.","m":[{"t":"Bệnh viện thực hiện ghép tạng rắn, mô và/hoặc tế bào tuân thủ mọi quy định do mạng lưới mua sắm và ghép tạng địa phương, khu vực hoặc quốc gia đặt ra.","b":[]},{"t":"Bệnh viện thực hiện ghép tạng rắn chia sẻ mọi dữ liệu liên quan đến quy trình ghép tạng theo yêu cầu của mạng lưới mua sắm và ghép tạng địa phương, khu vực hoặc quốc gia.","b":[]},{"t":"Bệnh viện xây dựng và duy trì các quy trình chuẩn hóa bằng văn bản để tiếp nhận, lưu trữ và cấp phát tạng, mô và/hoặc tế bào.","b":[]},{"t":"Bệnh viện xác minh tại thời điểm tiếp nhận tạng rằng tính toàn vẹn của bao bì đã được đáp ứng và phạm vi nhiệt độ vận chuyển đã được kiểm soát và chấp nhận được đối với tạng, mô và/hoặc tế bào. Xác minh này được ghi lại.","b":[]},{"t":"Bệnh viện tuân thủ hướng dẫn bằng văn bản của nhà cung cấp hoặc nhà sản xuất mô về việc vận chuyển, xử lý, lưu trữ và sử dụng mô.","b":[]},{"t":"Bệnh viện tuân thủ quy trình theo dõi các mô được cấy ghép.","b":[]},{"t":"Tủ lạnh, tủ đông, bình chứa nitơ và các thiết bị lưu trữ khác được sử dụng để lưu trữ các cơ quan, mô và tế bào ở nhiệt độ được kiểm soát có báo động chức năng và kế hoạch dự phòng khẩn cấp.","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"COP.09.06","ch":"COP","t":"Chương trình cấy ghép cần có sự đồng ý có thông tin cụ thể về việc cấy ghép nội tạng, mô và/hoặc tế bào từ ứng viên nhận ghép.","p":"Ghép tạng, mô và tế bào có những rủi ro riêng; để đưa ra quyết định sáng suốt về việc có nên tiến hành ghép\ntạng hay không, người nhận tiềm năng phải được thông báo về những rủi ro và thách thức này. Để đồng ý,\nbệnh nhân phải được thông báo về những yếu tố liên quan đến việc chăm sóc theo kế hoạch cần thiết cho\nmột quyết định sáng suốt. Bệnh nhân được thông báo về những yếu tố có thể ảnh hưởng đến sự thành công\ncủa ghép tạng hoặc sức khỏe của ứng viên với tư cách là người nhận.\n\nNgoài ra, có thể có những yếu tố về tâm lý, đạo đức, tài chính và các yếu tố khác riêng đối với bệnh nhân\nghép tạng, chẳng hạn như nhu cầu dùng thuốc ức chế miễn dịch và tỷ lệ sống sót dự kiến. Bệnh nhân cần\nđược thông báo về tất cả các cân nhắc đặc biệt như một phần của quy trình đồng ý. Chương trình ghép tạng\ncũng tuân theo chính sách của bệnh viện về sự đồng ý sáng suốt và luật pháp và quy định của địa phương và\nkhu vực.","m":[{"t":"Chương trình ghép tạng tuân theo chính sách bằng văn bản của bệnh viện khi lấy được sự đồng ý có thông tin từ các ứng viên ghép tạng đặc, mô và/hoặc tế bào. (Xem thêm PCC.03.00, MEs 1 và 2)","b":[]},{"t":"Chương trình ghép tạng thông báo cho ứng viên ghép tạng tiềm năng về các yếu tố rủi ro của người hiến tạng có thể ảnh hưởng đến sự thành công của ca ghép tạng hoặc sức khỏe của ứng viên với tư cách là người nhận, bao gồm nhưng không giới hạn ở những yếu tố sau:","b":["Tiền sử của người hiến tạng, phù hợp với luật pháp và quy định của quốc gia/khu vực","Tình trạng của các cơ quan được sử dụng","Tuổi của các cơ quan","Nguy cơ tiềm ẩn mắc bệnh truyền nhiễm nếu không phát hiện được bệnh ở người hiến tạng bị nhiễm bệnh","Rủi ro tâm lý xã hội tiềm ẩn"]},{"t":"Chương trình ghép tạng thông báo cho ứng viên ghép tạng tiềm năng về tỷ lệ sống sót sau một năm được quan sát và dự kiến của trung tâm ghép tạng sau khi ghép tạng đặc; hoặc, khi chương trình ghép tạng đã hoạt động chưa đầy 18 tháng, tỷ lệ sống sót sau một năm như đã ghi nhận trong tài liệu.","b":[]},{"t":"Chương trình cấy ghép thông báo cho ứng viên cấy ghép nội tạng rắn, mô và/hoặc tế bào tiềm năng về tỷ lệ đào thải tiềm ẩn, thuốc ức chế miễn dịch và các chi phí liên quan có thể có, tùy theo loại cấy ghép.","b":[]},{"t":"Chương trình cấy ghép thông báo cho ứng viên cấy ghép nội tạng rắn, mô và/hoặc tế bào tiềm năng về các phương pháp điều trị thay thế.","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"COP.09.07","ch":"COP","t":"Chương trình cấy ghép đã ghi chép các giao thức, hướng dẫn thực hành lâm sàng hoặc quy trình phục hồi nội tạng và tiếp nhận nội tạng để đảm bảo tính tương thích, an toàn, hiệu quả và chất lượng của tế bào, mô và nội tạng của con người để cấy ghép.","p":"Để giảm nguy cơ đào thải cơ quan, mô hoặc tế bào, bác sĩ phẫu thuật ghép tạng phải đảm bảo tính\ntương thích của cơ quan, mô và/hoặc tế bào của người hiến tặng với người nhận. Việc lây truyền các\nbệnh truyền nhiễm và bệnh ác tính là nguy cơ tiềm ẩn đối với người nhận tế bào, mô và cơ quan của\nngười hiến tặng.\n\nDo đó, mức độ an toàn, hiệu quả và chất lượng của tế bào, mô và cơ quan của con người để ghép\ntạng phải được đảm bảo. Đánh giá người hiến tặng cơ quan và mô có thể xác định những người hiến\ntặng có nguy cơ nhiễm trùng cao hơn với tác nhân gây bệnh có khả năng gây hại. Việc sàng lọc tiền sử\nlâm sàng của người hiến tặng và xét nghiệm bệnh truyền nhiễm của người hiến tặng có thể làm giảm\nđáng kể tỷ lệ lây truyền bệnh của người hiến tặng. Sàng lọc người hiến tặng nên bao gồm đánh giá tiền\nsử bệnh, các yếu tố nguy cơ về hành vi và khám sức khỏe. Xét nghiệm người hiến tặng nên bao gồm xét\nnghiệm HIV, viêm gan B, viêm gan C và các xét nghiệm được khuyến nghị khác.\n\n(C P)\n\nCác xét nghiệm thường được sử dụng nhất để xác định khả năng tương thích bao gồm nhóm máu và xét nghiệm chéo và\nphân loại mô. Bác sĩ phẫu thuật ghép đảm bảo rằng việc xét nghiệm khả năng tương thích được thực hiện trước khi phục\nhồi nội tạng và ghép tạng diễn ra. Đối với bất kỳ ca ghép tạng nào, cần đảm bảo khả năng truy xuất nguồn gốc trong suốt\ncuộc đời dự kiến của người hiến tặng và người nhận. Các phương tiện mã hóa được quốc tế thống nhất để xác định các mô\nvà tế bào được sử dụng trong quá trình ghép tạng là điều cần thiết để có thể truy xuất nguồn gốc đầy đủ.","m":[{"t":"Nhóm ghép tạng tuân theo các giao thức phục hồi nội tạng bằng văn bản, hướng dẫn thực hành lâm sàng hoặc quy trình, bao gồm việc xem xét dữ liệu cần thiết của người hiến tặng và dữ liệu của người nhận để đảm bảo tính tương thích trước khi tiến hành phục hồi nội tạng, mô hoặc tế bào.","b":[]},{"t":"Bác sĩ phẫu thuật ghép tạng có trách nhiệm xác nhận bằng văn bản về tính phù hợp về mặt y tế của nội tạng, mô và tế bào của người hiến tặng để cấy ghép vào người nhận.","b":[]},{"t":"Khi nội tạng hoặc mô đến trung tâm ghép tạng, bác sĩ phẫu thuật ghép tạng và ít nhất một bác sĩ chăm sóc sức khỏe khác tại trung tâm ghép tạng sẽ xác minh và ghi lại rằng nhóm máu của người hiến tặng và các dữ liệu cần thiết khác tương thích với người nhận trước khi ghép tạng.","b":[]},{"t":"Bác sĩ phẫu thuật ghép tạng có trách nhiệm xác nhận rằng quá trình đánh giá người hiến tặng và xét nghiệm bệnh truyền nhiễm và ác tính của người hiến tặng đã hoàn tất và được ghi lại trong hồ sơ y tế trước khi tiến hành phục hồi và ghép tạng, mô hoặc tế bào.","b":[]},{"t":"Khi một cơ quan đến trung tâm cấy ghép, bác sĩ phẫu thuật cấy ghép và ít nhất một bác sĩ chăm sóc sức khỏe khác tại trung tâm cấy ghép sẽ xác minh và ghi lại rằng việc đánh giá và xét nghiệm cơ quan của người hiến tặng không cho thấy bằng chứng về bệnh tật và tình trạng của cơ quan đó phù hợp để cấy ghép.","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"COP.09.08","ch":"COP","t":"Hướng dẫn thực hành lâm sàng và tiêu chuẩn lâm sàng hướng dẫn việc lựa chọn và chăm sóc bệnh nhân ghép tạng, mô và tế bào.","p":"Các kế hoạch chăm sóc cá nhân được xây dựng và hướng dẫn việc chăm sóc bệnh nhân ghép tạng kết hợp với\ncác hướng dẫn thực hành lâm sàng, vì việc chăm sóc bệnh nhân hiến tặng hoặc nhận ghép tế bào, cơ quan\nhoặc mô dựa trên loại ghép và nhu cầu cá nhân. Tiền sử sức khỏe của bệnh nhân có tác động đến quá trình\nphục hồi của họ. Ngoài ra, tình trạng tâm lý của bệnh nhân có thể ảnh hưởng đến sự thành công của ca ghép\ntạng. Đánh giá tâm lý sẽ được thực hiện bởi bác sĩ tâm thần, nhà tâm lý học, nhân viên xã hội hoặc chuyên gia\nchăm sóc sức khỏe đủ tiêu chuẩn khác có kinh nghiệm về ghép tạng để xác định khả năng ra quyết định của\nbệnh nhân và sàng lọc bất kỳ bệnh tâm thần nào có từ trước.","m":[{"t":"Chương trình cấy ghép đã ghi lại các hướng dẫn thực hành lâm sàng cụ thể về tế bào, mô và/hoặc cơ quan cho các giai đoạn trước khi cấy ghép, cấy ghép và xuất viện của ca cấy ghép.","b":[]},{"t":"Mỗi bệnh nhân cấy ghép đều được chăm sóc bởi một nhóm chăm sóc bệnh nhân đa chuyên khoa do bác sĩ cấy ghép chính của bệnh nhân điều phối trong suốt các giai đoạn trước khi cấy ghép, cấy ghép và xuất viện của ca cấy ghép.","b":[]},{"t":"Các ứng viên nhận ghép được đánh giá về tính phù hợp của các liệu pháp y tế và phẫu thuật khác có thể mang lại tỷ lệ sống sót ngắn hạn và dài hạn tương đương với cấy ghép.","b":[]},{"t":"Các ứng viên nhận ghép được bác sĩ tâm thần, nhà tâm lý học, nhân viên xã hội hoặc chuyên gia chăm sóc sức khỏe đủ tiêu chuẩn khác có kinh nghiệm về cấy ghép đánh giá tâm lý để xác định khả năng ra quyết định của bệnh nhân và sàng lọc bất kỳ bệnh tâm thần nào có từ trước.","b":[]},{"t":"Chương trình cấy ghép cập nhật thông tin lâm sàng trong hồ sơ y tế của người hiến tặng và/hoặc người nhận ghép một cách liên tục.","b":[]},{"t":"Chương trình cấy ghép ghi lại xác nhận khả năng tương thích của cơ quan trong hồ sơ y tế của người hiến tặng còn sống. (C P) Chương trình cấy ghép sử dụng nội tạng của người hiến tặng còn sống","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"COP.10.00","ch":"COP","t":"Các chương trình cấy ghép thực hiện cấy ghép từ người hiến tặng còn sống tuân thủ luật pháp và quy định của địa phương và khu vực và bảo vệ quyền của người hiến tặng tiềm năng hoặc thực tế còn sống.","p":"Người hiến tặng còn sống phải đối mặt với những quyết định khó khăn và có nguy cơ gặp phải các biến\nchứng suốt đời và không nên cảm thấy bị ép buộc hoặc gây áp lực phải hiến tặng nội tạng. Nhu cầu ngày\ncàng tăng và nguồn cung cấp nội tạng hạn chế từ người hiến tặng đã dẫn đến những nỗ lực tăng cường\nthúc đẩy hiến tặng nội tạng sống. Các tiêu chuẩn của người hiến tặng còn sống để lựa chọn ứng viên phù\nhợp cho việc hiến tặng, sự đồng ý có thông tin và chăm sóc sau khi hiến tặng không tồn tại ở mọi nơi.\n\nĐể hỗ trợ đưa ra quyết định và đảm bảo rằng quyền của người hiến tặng còn sống được bảo vệ, một cá\nnhân có kiến thức về hiến tặng nội tạng sống, cấy ghép, đạo đức y khoa và sự đồng ý có thông tin sẽ được\nxác định và bổ nhiệm để bảo vệ quyền của bệnh nhân. Người này độc lập với nhóm cấy ghép và nếu được\nbệnh viện tuyển dụng thì không báo cáo với bất kỳ thành viên nào trong nhóm cấy ghép. Mục tiêu của\nngười này là đảm bảo rằng người hiến tặng còn sống hiểu được mọi khía cạnh của quy trình hiến tặng và\ntự chủ trong khả năng ra quyết định của mình.","m":[{"t":"Các chương trình cấy ghép thực hiện cấy ghép từ người hiến tặng còn sống tuân thủ luật pháp và quy định của địa phương và khu vực.","b":[]},{"t":"Người hiến tặng nội tạng sống có quyền đưa ra quyết định về việc hiến tặng trong một môi trường không bị ép buộc và áp lực.","b":[]},{"t":"Một cá nhân có kiến thức về hiến tặng nội tạng sống, cấy ghép, đạo đức y khoa và sự đồng ý có thông tin đầy đủ được xác định và chỉ định làm người ủng hộ cho người hiến tặng còn sống.","b":[]},{"t":"Cá nhân được chỉ định làm người ủng hộ người hiến tặng còn sống không tham gia vào các hoạt động cấy ghép thông thường.","b":[]},{"t":"Cá nhân được chỉ định làm người ủng hộ người hiến tặng còn sống thông báo, hỗ trợ và tôn trọng người hiến tặng còn sống theo cách phù hợp với văn hóa trong quá trình ra quyết định.","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"COP.10.01","ch":"COP","t":"Các chương trình cấy ghép thực hiện cấy ghép từ người hiến tặng còn sống phải có sự đồng ý được thông báo cụ thể về việc hiến tặng nội tạng từ người hiến tặng còn sống tiềm năng.","p":"Người hiến tặng tiềm năng cần hiểu rõ mọi khía cạnh của quá trình hiến tặng, đặc biệt là hiểu các rủi ro và lợi ích\nliên quan đến việc trở thành người hiến tặng khi còn sống. Nhiều người hiến tặng khi còn sống hiến tặng nội tạng\ncủa họ cho một thành viên gia đình hoặc người quen; tuy nhiên, một số người hiến tặng khi còn sống không ảnh\nhưởng đến vị trí của nội tạng được hiến tặng của họ. Một khía cạnh rất quan trọng của việc có được sự đồng ý có\nhiểu biết là đảm bảo rằng người hiến tặng tiềm năng sẵn sàng hiến tặng và không bị ép buộc hoặc hứa hẹn bồi\nthường và hiểu rằng họ có thể từ chối hiến tặng bất cứ lúc nào. Quá trình đồng ý bao gồm thông tin được cung cấp\ncho bất kỳ bệnh nhân nào đang trải qua gây mê, an thần hoặc phẫu thuật và thông tin cụ thể về việc cấy ghép.\n\n(C P)","m":[{"t":"Sự đồng ý được thông báo cho việc hiến tặng khi còn sống được lấy từ đội ngũ nhân viên được đào tạo và được viết bằng ngôn ngữ mà người hiến tặng tiềm năng có thể hiểu được. (Xem thêm PCC.03.00, MEs 1 và 2)","b":[]},{"t":"Chương trình ghép tạng thông báo cho người hiến tặng tiềm năng về các biến chứng, rủi ro tiềm ẩn (bao gồm rủi ro về mặt tâm lý) và các vấn đề sức khỏe trong tương lai liên quan đến việc hiến tặng nội tạng khi còn sống.","b":[]},{"t":"Chương trình ghép tạng thông báo cho người hiến tặng tiềm năng về các phương pháp điều trị thay thế cho ứng viên ghép tạng.","b":[]},{"t":"Chương trình ghép tạng thông báo cho người hiến tặng tiềm năng về quyền từ chối hiến tặng của người hiến tặng bất kỳ lúc nào trong quá trình hiến tặng.","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"COP.10.02","ch":"COP","t":"Các chương trình cấy ghép thực hiện cấy ghép từ người hiến tặng còn sống sử dụng các tiêu chí lựa chọn về mặt lâm sàng và tâm lý để xác định tính phù hợp của những người hiến tặng còn sống tiềm năng.","p":"Người hiến tặng nội tạng phải được đánh giá về sự phù hợp, cả về thể chất và tâm lý, với tư cách là người\nhiến tặng nội tạng. Đánh giá y tế xác định khả năng thể chất của người hiến tặng để hiến tặng và xác định bất\nkỳ rủi ro sức khỏe tức thời nào và rủi ro sức khỏe có thể xảy ra trong tương lai. Đánh giá tâm lý sẽ được tiến\nhành bởi bác sĩ tâm thần, nhà tâm lý học hoặc nhân viên xã hội có kinh nghiệm về cấy ghép để xác định khả\nnăng ra quyết định, sàng lọc bất kỳ bệnh tâm thần nào có từ trước và đánh giá bất kỳ sự ép buộc tiềm ẩn nào.\nNgười hiến tặng cũng phải được đánh giá về khả năng hiểu được quy trình hiến tặng và các kết quả tiềm ẩn,\nbao gồm cả các kết quả bất lợi có thể xảy ra.","m":[{"t":"Chương trình cấy ghép ghi lại các tiêu chí lựa chọn người hiến tặng còn sống cụ thể cho từng cơ quan.","b":[]},{"t":"Các tiêu chí lựa chọn người hiến tặng còn sống của chương trình cấy ghép phù hợp với luật pháp và quy định cũng như các nguyên tắc về đạo đức y khoa. (Xem thêm GLD.07.00, ME 1)","b":[]},{"t":"Kết quả đánh giá y tế liên quan đến sức khỏe thể chất của chính người hiến tặng còn sống được đưa vào quá trình xác định tính phù hợp để hiến tặng.","b":[]},{"t":"Kết quả xét nghiệm y tế xác định bệnh truyền nhiễm hoặc bệnh ác tính được đưa vào quá trình xác định tính phù hợp để hiến tặng.","b":[]},{"t":"Kết quả đánh giá tâm lý do bác sĩ tâm thần, nhà tâm lý học hoặc nhân viên xã hội có kinh nghiệm về cấy ghép thực hiện được ghi lại trong hồ sơ y tế của người hiến tặng còn sống và được đưa vào quá trình xác định tính phù hợp để hiến tặng.","b":[]},{"t":"Chương trình cấy ghép ghi lại xác nhận về tính tương thích của cơ quan trong hồ sơ y tế của người hiến tặng còn sống.","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"COP.10.03","ch":"COP","t":"Các kế hoạch chăm sóc bệnh nhân được cá nhân hóa hướng dẫn việc chăm sóc những người hiến tặng còn sống.","p":"Người hiến tặng còn sống có nhu cầu điều trị và chăm sóc sức khỏe riêng biệt cần được cân nhắc cụ thể. Các kế hoạch\nchăm sóc cá nhân được xây dựng và triển khai cho tất cả người hiến tặng còn sống. Việc ghép tạng từ người hiến tặng\ncòn sống được hướng dẫn theo hướng dẫn của người hiến tặng còn sống. Tuy nhiên, người hiến tặng có nhu cầu cá\nnhân phải được giải quyết thông qua kế hoạch chăm sóc cẩn thận. Việc chăm sóc người hiến tặng được điều phối bởi\nbác sĩ và được thực hiện bởi một nhóm đa chuyên khoa để đảm bảo rằng nhu cầu của người hiến tặng được đáp ứng\ntrước, trong và sau khi hiến tặng.\n\n(C P)","m":[{"t":"Các chương trình cấy ghép thực hiện cấy ghép từ người hiến tặng còn sống được hướng dẫn bởi các hướng dẫn dành cho người hiến tặng còn sống được ghi chép lại để chăm sóc trong các giai đoạn đánh giá, hiến tặng và xuất viện của quá trình hiến tặng.","b":[]},{"t":"Các chương trình cấy ghép thực hiện cấy ghép từ người hiến tặng còn sống cung cấp dịch vụ chăm sóc liên ngành do một nhóm do bác sĩ điều phối cho từng người hiến tặng trong suốt quá trình đánh giá, hiến tặng và xuất viện của quá trình hiến tặng.","b":[]},{"t":"Ứng viên hiến tặng còn sống nhận được hỗ trợ tâm lý liên tục sau khi hiến tặng. Mục tiêu an toàn bệnh nhân quốc tế (IPSG) Mục tiêu an toàn bệnh nhân quốc tế Tổng quan Chương này đề cập đến Mục tiêu An toàn Bệnh nhân Quốc tế (IPSG), bắt buộc phải triển khai kể từ ngày 1 tháng 1 năm 2011 tại tất cả các tổ chức được Ủy ban Liên hợp Quốc tế (JCI) công nhận theo Tiêu chuẩn Công nhận Quốc tế cho Bệnh viện. Mục đích của Mục tiêu An toàn Bệnh nhân Quốc tế là thúc đẩy những cải thiện cụ thể về an toàn bệnh nhân. Các mục tiêu nêu bật các lĩnh vực có vấn đề trong chăm sóc sức khỏe và mô tả các giải pháp đồng thuận dựa trên bằng chứng và chuyên gia cho những vấn đề này. Nhận ra rằng thiết kế hệ thống hợp lý là nội tại đối với việc cung cấp dịch vụ chăm sóc sức khỏe an toàn, chất lượng cao, các mục tiêu thường tập trung vào các giải pháp toàn hệ thống, bất cứ khi nào có thể. Các mục tiêu được cấu trúc theo cùng cách như các tiêu chuẩn khác, bao gồm một tiêu chuẩn (tuyên bố mục tiêu), một tuyên bố về ý định và các yếu tố có thể đo lường (ME). Các mục tiêu được chấm điểm tương tự như các tiêu chuẩn khác là \"đạt\" hoặc \"không đạt\". Các quy tắc quyết định công nhận bao gồm việc tuân thủ các mục tiêu như một quy tắc quyết định riêng biệt. Mục tiêu và tiêu chuẩn Sau đây là danh sách tất cả các mục tiêu và tiêu chuẩn cho chức năng này. Chúng được trình bày ở đây để bạn tiện theo dõi mà không có các tuyên bố về ý định hoặc các yếu tố có thể đo lường. Để biết thêm thông tin về các tiêu chuẩn này, vui lòng xem phần tiếp theo trong chương này, Mục tiêu, Tiêu chuẩn, Ý định và Các yếu tố có thể đo lường. Mục tiêu 1: Xác định đúng bệnh nhân IPSG.01.00 Bệnh viện triển khai quy trình nâng cao độ chính xác trong việc nhận dạng bệnh nhân. Mục tiêu 2: Cải thiện giao tiếp hiệu quả IPSG.02.00 Bệnh viện thực hiện quy trình báo cáo kết quả quan trọng của các xét nghiệm chẩn đoán. IPSG.02.01 Bệnh viện triển khai quy trình chuẩn hóa cho việc trao đổi thông tin. Mục tiêu 3: Cải thiện tính an toàn của thuốc IPSG.03.00 Bệnh viện triển khai quy trình cải thiện tính an toàn của thuốc có mức cảnh báo cao. IPSG.03.01 Bệnh viện triển khai quy trình cải thiện tính an toàn của các loại thuốc có tên gọi/tên gọi tương tự. IPSG.03.02 Bệnh viện triển khai quy trình quản lý sử dụng an toàn chất điện giải cô đặc. Mục tiêu 4: Đảm bảo phẫu thuật an toàn IPSG.04.00 Bệnh viện thực hiện quy trình xác minh trước phẫu thuật và đánh dấu vị trí phẫu thuật/xâm lấn. IPSG.04.01 Bệnh viện thực hiện quy trình tạm dừng được thực hiện ngay trước khi bắt đầu thủ thuật phẫu thuật/xâm lấn và thủ thuật đăng xuất được thực hiện sau thủ thuật. Mục tiêu 5: Giảm nguy cơ nhiễm trùng liên quan đến chăm sóc sức khỏe IPSG.05.00 Bệnh viện thực hiện các hướng dẫn vệ sinh tay dựa trên bằng chứng để giảm nguy cơ nhiễm trùng liên quan đến chăm sóc sức khỏe. Mục tiêu, Tiêu chuẩn, Ý định và Các yếu tố có thể đo lường Mục tiêu 1: Xác định bệnh nhân một cách chính xác","b":[]}],"sec":"Bệnh viện cung cấp dịch vụ cấy ghép"},{"c":"FMS.01.00","ch":"FMS","t":"Bệnh viện tuân thủ các luật, quy định có liên quan, quy định về an toàn xây dựng và phòng cháy chữa cháy và các yêu cầu kiểm tra cơ sở.","p":"Luật pháp, quy định và thanh tra của chính quyền địa phương và quốc gia quyết định phần lớn cách\nthiết kế, sử dụng và bảo trì cơ sở. Tất cả các bệnh viện, bất kể quy mô và nguồn lực, đều phải tuân thủ\ncác yêu cầu này như một phần trách nhiệm của họ đối với bệnh nhân, gia đình, nhân viên và khách đến\nthăm.\n\nCác yêu cầu có thể khác nhau tùy thuộc vào thời điểm cơ sở được xây dựng và phê duyệt. Ví dụ, nhiều\nquy định về xây dựng tòa nhà và quy định về an toàn phòng cháy chữa cháy, chẳng hạn như đối với hệ\nthống phun nước, chỉ áp dụng cho công trình xây dựng mới. Bệnh viện bắt đầu bằng việc tuân thủ luật\npháp và quy định.\n\nQuản lý và an\ntoàn cơ sở (FMS)\n\nMột số bệnh viện nằm bên trong các tòa nhà lớn hơn, đa chức năng, chẳng hạn như các tòa nhà văn phòng cao\ntầng và trung tâm mua sắm, và có thể cho thuê hoặc thuê lại không gian mà họ cung cấp dịch vụ chăm sóc, điều\ntrị và dịch vụ. Trong những trường hợp này, các nhà lãnh đạo bệnh viện cần phải trao đổi với chủ sở hữu bất\nđộng sản để đảm bảo rằng tòa nhà tuân thủ các luật, quy định, quy tắc và các yêu cầu khác có liên quan. Ngoài\nra, các nhà lãnh đạo bệnh viện phải trao đổi và hợp tác với chủ sở hữu bất động sản về các hệ thống tòa nhà\nchung và các vấn đề liên quan đến tòa nhà không nằm trong tầm kiểm soát của bệnh viện. Điều quan trọng là\nphải hiểu được kỳ vọng và ai chịu trách nhiệm bảo trì các hệ thống này. Các hệ thống chung và các vấn đề về\ntòa nhà có thể bao gồm an ninh và an toàn phòng cháy chữa cháy. Ví dụ bao gồm hệ thống giám sát video, báo\ncháy và báo động ra vào, hệ thống chữa cháy, lối thoát hiểm, bảo trì tiện ích, điện, thông gió, chất lượng nước\nvà các vấn đề khác của tòa nhà. Điều quan trọng là các nhà lãnh đạo bệnh viện phải có quyền truy cập vào các\ntài liệu do chủ sở hữu bất động sản quản lý, chẳng hạn như hồ sơ bảo trì và báo cáo kiểm tra liên quan đến các\ncơ sở của bệnh viện. Các nhà lãnh đạo bệnh viện đánh giá mức độ tuân thủ của bất động sản để xác định rằng\ncác tiện ích và cơ sở thuộc về chủ sở hữu được quản lý phù hợp để đáp ứng nhu cầu của bệnh nhân.\n\nLãnh đạo bệnh viện và cơ cấu quản lý và an toàn cơ sở của bệnh viện chịu trách nhiệm về những điều sau:\n• Biết luật, quy định, quy tắc an toàn xây dựng và phòng cháy chữa cháy quốc gia và địa phương, cùng các yêu\ncầu khác, chẳng hạn như giấy phép và giấy phép, áp dụng cho các cơ sở của bệnh viện\n• Triển khai các yêu cầu áp dụng hoặc các yêu cầu thay thế được chấp thuận\n• Duy trì và ghi chép việc tuân thủ luật, quy định, quy tắc an toàn xây dựng và phòng cháy chữa cháy, báo cáo\nkiểm tra và các yêu cầu khác của cơ sở\n• Lên kế hoạch và lập ngân sách cho việc thay thế hoặc nâng cấp cần thiết các cơ sở, hệ thống và thiết bị để\nđáp ứng các yêu cầu áp dụng hoặc được xác định bằng dữ liệu giám sát và cung cấp\n• bằng chứng về tiến độ thực hiện các cải tiến\n\nKhi bệnh viện bị trích dẫn vì không đáp ứng các yêu cầu, lãnh đạo bệnh viện có trách nhiệm lập kế hoạch và\nđáp ứng các yêu cầu trong khung thời gian quy định.\n\nBệnh viện lập tài liệu về luật, quy định và quy tắc an toàn xây dựng và phòng cháy chữa cháy của mình và mọi\nhành động khắc phục được thực hiện để giải quyết các trích dẫn từ các cuộc thanh tra và báo cáo bên ngoài cơ\nsở. Khi bệnh viện nằm bên trong một tòa nhà đa chức năng, bệnh viện phải tuân thủ các luật, quy định và báo\ncáo thanh tra cơ sở có liên quan, yêu cầu bảo trì tiện ích và các yêu cầu khác liên quan đến các hệ thống dùng\nchung và các vấn đề về tòa nhà. Khi các nhà lãnh đạo bệnh viện không thể nhận được báo cáo về các cuộc thanh\ntra và tài liệu, cần phải có một nỗ lực đáng tin cậy (ví dụ, tài liệu về các nỗ lực giao tiếp với chủ sở hữu tòa\nnhà).\n\nCác yếu tố đo lường được của FMS.01.00\n1.\nLãnh đạo bệnh viện thực hiện luật pháp, quy định, quy tắc an toàn xây dựng và phòng cháy chữa\ncháy của quốc gia và địa phương, và các yêu cầu khác áp dụng cho các cơ sở của bệnh viện.\n2. Các hành động khắc phục được thực hiện để đáp ứng các điều kiện của báo cáo và thanh tra cơ sở bên\nngoài của các cơ quan chức năng quốc gia và địa phương được ghi lại.\n3. Lãnh đạo bệnh viện lập kế hoạch và lập ngân sách để thay thế hoặc nâng cấp các cơ sở, hệ thống và\nthiết bị cần thiết để đáp ứng các yêu cầu và để tiếp tục vận hành một cơ sở an toàn, bảo mật và\nhiệu quả.\n4. Khi bệnh viện nằm bên trong một tòa nhà đa năng, lãnh đạo bệnh viện phải có bằng chứng về việc\ntuân thủ các luật pháp, quy định, quy tắc, báo cáo thanh tra cơ sở, yêu cầu bảo trì tiện ích và các yêu\ncầu khác liên quan đến các vấn đề về hệ thống và tòa nhà dùng chung.","m":[],"sec":"Lãnh đạo và lập kế hoạch"},{"c":"FMS.01.01","ch":"FMS","t":"Một hoặc nhiều cá nhân có trình độ sẽ giám sát việc quản lý cơ sở và cấu trúc an toàn.","p":"Bệnh viện làm việc để cung cấp các cơ sở an toàn, chức năng và hỗ trợ cho bệnh nhân, gia đình, nhân viên và\nkhách thăm. Bệnh viện phải cố gắng thực hiện các điều sau:\n\n•\nGiảm thiểu và kiểm soát các mối nguy hiểm và rủi ro.\n•\nPhòng ngừa tai nạn và thương tích.\n•\nDuy trì các điều kiện an toàn.\n\nQuản lý hiệu quả bao gồm lập kế hoạch đa ngành, giáo dục và giám sát như sau:\n•\nLãnh đạo bệnh viện lập kế hoạch về không gian, công nghệ và nguồn lực cần thiết để hỗ trợ an toàn và hiệu quả\ncác dịch vụ lâm sàng và phi lâm sàng được cung cấp.\n•\nNhân viên có liên quan được đào tạo về cơ sở, cách giảm thiểu rủi ro và cách giám sát và báo cáo các tình huống\ngây ra rủi ro.\n•\nTiêu chí hiệu suất được sử dụng để đánh giá các hệ thống quan trọng và xác định các cải tiến cần thiết.\n\nLãnh đạo bệnh viện xác định một cá nhân đủ điều kiện về đào tạo và kinh nghiệm để giám sát cơ cấu quản lý và an toàn\ncơ sở. Đào tạo và kinh nghiệm có thể bao gồm nhưng không giới hạn ở quản lý rủi ro, quản lý cơ sở và hoạt động của\nbệnh viện. Cá nhân giám sát cơ cấu có thể là thành viên của nhóm lãnh đạo, người lãnh đạo phụ trách một hoặc nhiều\nchương trình quản lý và an toàn cơ sở hoặc một cá nhân được chỉ định khác. Tất cả các chương trình quản lý và an toàn\ncơ sở đều báo cáo với cá nhân này, người chịu trách nhiệm tích hợp và phối hợp các hoạt động và chức năng của toàn bộ\ncơ cấu quản lý và an toàn cơ sở. Trong một bệnh viện nhỏ, một cá nhân có thể được phân công bán thời gian để giám sát\ncấu trúc. Trong một bệnh viện lớn hơn, một số kỹ sư hoặc những cá nhân được đào tạo đặc biệt khác có thể được phân\ncông để quản lý một hoặc nhiều chương trình quản lý cơ sở và an toàn theo chỉ đạo của cá nhân chịu trách nhiệm về toàn\nbộ cấu trúc.\nCấu trúc quản lý cơ sở và an toàn phải được quản lý hiệu quả, nhất quán và liên tục.\nTùy thuộc vào quy mô và mức độ phức tạp của bệnh viện, một ủy ban rủi ro về môi trường/an toàn cơ sở hoặc một số cơ\nchế khác có thể được thành lập để hỗ trợ cá nhân chịu trách nhiệm về cấu trúc quản lý cơ sở và an toàn. Ví dụ, ủy ban này\ncó thể điều phối các hoạt động của các chương trình quản lý cơ sở và an toàn, chẳng hạn như hoàn thành các hoạt động\nđánh giá rủi ro, phân tích dữ liệu giám sát và triển khai các cải tiến cho cơ sở. Cơ chế do bệnh viện lựa chọn để hỗ trợ cá\nnhân chịu trách nhiệm về cấu trúc quản lý cơ sở và an toàn phải xem xét một nhóm đa ngành và bao gồm đại diện từ các\nchương trình quản lý cơ sở và an toàn khác nhau, ban lãnh đạo, phòng ngừa và kiểm soát nhiễm trùng, các chương trình\nan toàn phòng thí nghiệm và bức xạ, an toàn laser, dịch vụ dọn dẹp và chương trình chất lượng và an toàn cho bệnh nhân,\ncùng nhiều chương trình khác.\n\nKhi các thực thể kinh doanh độc lập có mặt trong tổ chức, bệnh viện có nghĩa vụ đảm bảo rằng các thực thể này tuân thủ\ncác chương trình quản lý cơ sở và an toàn có liên quan. Các thực thể kinh doanh độc lập là các doanh nghiệp sở hữu độc\nlập chiếm không gian trong bệnh viện (ví dụ: quán cà phê, cửa hàng quà tặng, ngân hàng).\n\nCác yếu tố đo lường được của FMS.01.01\n1.\nGiám sát và chỉ đạo cơ cấu quản lý và an toàn cơ sở được giao cho một hoặc nhiều cá nhân\ncó trình độ về kinh nghiệm và đào tạo, và bằng chứng về kinh nghiệm và đào tạo được ghi\nlại. (Xem thêm GLD.06.00, ME 1)\n2. Cá nhân có trình độ có trách nhiệm đảm bảo những điều sau:\n•\nCác khuyến nghị về không gian, công nghệ và các nguồn lực khác để hỗ trợ cơ cấu quản\nlý và an toàn cơ sở được cung cấp cho các nhà lãnh đạo bệnh viện.\n•\nCác chương trình quản lý và an toàn cơ sở được cập nhật và triển khai đầy đủ.\n•\nNhân viên và những người khác được đào tạo về các chương trình.\n•\nCác chương trình được phối hợp, đánh giá và giám sát.\n•\nCác chương trình được xem xét và sửa đổi ít nhất hàng năm hoặc thường xuyên hơn nếu\ncần (ví dụ: khi có thay đổi về các yêu cầu trong luật pháp và quy định của quốc gia hoặc\nthay đổi về cơ sở, hệ thống hoặc thiết bị của bệnh viện).\n3.  Khi có các thực thể kinh doanh độc lập trong tổ chức, các thực thể này tuân thủ các chương\ntrình quản lý và an toàn cơ sở hiện hành.\n\nĐánh giá và giám sát rủi ro","m":[],"sec":"Lãnh đạo và lập kế hoạch"},{"c":"FMS.02.00","ch":"FMS","t":"Bệnh viện xây dựng và ghi chép đánh giá rủi ro dựa trên các rủi ro về quản lý cơ sở và an toàn được xác định trong toàn bộ tổ chức, ưu tiên các rủi ro, thiết lập mục tiêu và thực hiện các cải tiến để giảm thiểu và loại bỏ rủi ro.","p":"Đánh giá rủi ro xác định và đánh giá các lỗi tiềm ẩn và nguồn lỗi trong một quy trình và bao gồm việc ưu tiên\ncác lĩnh vực cần cải thiện dựa trên tác động thực tế hoặc tiềm ẩn của việc chăm sóc, điều trị hoặc các dịch\nvụ được cung cấp.\n\nBệnh viện phát triển và lập hồ sơ đánh giá rủi ro trên toàn cơ sở, ít nhất là hàng năm, tích hợp tất cả tám\nchương trình quản lý và an toàn cơ sở để tối đa hóa sự an toàn cho bệnh nhân, gia đình bệnh nhân, nhân\nviên và khách thăm. Ví dụ, các rủi ro bao gồm nhưng không giới hạn ở các rủi ro về an toàn/bảo mật liên\nquan đến bắt cóc trẻ sơ sinh hoặc xả súng; rủi ro từ chất thải nguy hại như vật liệu bị nhiễm máu hoặc dịch\ncơ thể, hoặc xử lý các hóa chất nguy hại như thuốc khử trùng cấp độ cao và chất khử trùng hóa học; rủi ro\nhỏa hoạn cụ thể như cháy phẫu thuật (khi sử dụng chế phẩm da gốc cồn với các thiết bị đốt điện), hoặc\ncháy điện hoặc cháy mỡ trong bếp; rủi ro hệ thống tiện ích như mất nguồn điện bên ngoài hoặc rủi ro quản\nlý nước từ các tác nhân gây bệnh trong nước như vi khuẩn Legionella; rủi ro từ hệ thống ống nước hoặc rò\nrỉ nước trên mái nhà trong tòa nhà dẫn đến nấm mốc nguy hiểm phát triển; rủi ro từ hệ thống khí y tế hoặc\nhệ thống chân không như rủi ro nổ; hoặc rủi ro xây dựng liên quan đến bụi và sự phát tán bào tử nấm gần\nbệnh nhân dễ bị tổn thương hoặc vật liệu nguy hiểm như amiăng. Bệnh viện ưu tiên các rủi ro cụ thể được\nxác định trong đánh giá rủi ro. Các mục tiêu được thiết lập và các cải tiến được thực hiện để giảm và loại bỏ\ncác rủi ro. Các mục tiêu và cải tiến được theo dõi về hiệu quả, bao gồm cải tiến đang tiến triển và duy trì. Có\nthể cần thay đổi các mục tiêu và cải tiến dựa trên những thành công và thách thức được xác định trong dữ\nliệu giám sát.\n\nCác yếu tố đo lường được của FMS.02.00\n1. Bệnh viện xây dựng và triển khai đánh giá rủi ro hàng năm bao gồm tám chương trình quản lý cơ\nsở và an toàn:\n•\nAn toàn (Xem thêm FMS.03.00, ME 2)\n•\nAn ninh\n•\nVật liệu và chất thải nguy hại\n•\nAn toàn cháy nổ (Xem thêm FMS.06.00, ME 3)\n•\nThiết bị y tế\n•\nHệ thống tiện ích\n•\nQuản lý tình trạng khẩn cấp và thảm họa (Xem thêm GHI.05.00, ME 4)\n•\nXây dựng và cải tạo (Xem thêm FMS.10.00, ME 1)\n2. Bệnh viện ưu tiên các rủi ro, xác định các mục tiêu và cải tiến hiệu suất chính, và\ntriển khai các cải tiến để giảm thiểu và loại bỏ rủi ro. (Xem thêm GLD.06.01, ME 1)\n3. Bệnh viện đánh giá hiệu quả của các cải tiến và dựa trên kết quả, bệnh viện\ncập nhật các chương trình quản lý cơ sở và an toàn hiện hành. (Xem thêm GLD.06.01, ME 2)\n4. Các nhà lãnh đạo bệnh viện cung cấp báo cáo đánh giá rủi ro hàng năm và hiệu quả của các chương\ntrình quản lý và an toàn cơ sở cho cơ quan quản lý, và cơ quan quản lý thực hiện các hành động\ndựa trên báo cáo. (Xem thêm GLD.04.01, ME 1)\n\nAn toàn","m":[],"sec":"Đánh giá và giám sát rủi ro"},{"c":"FMS.03.00","ch":"FMS","t":"Bệnh viện thực hiện chương trình cung cấp cơ sở vật chất an toàn.","p":"An toàn có nghĩa là đảm bảo rằng tòa nhà, tài sản, công nghệ thông tin và y tế, thiết bị và hệ thống không gây ra rủi ro về\nan toàn vật lý cho bệnh nhân, gia đình, nhân viên và khách đến thăm. Phòng ngừa và lập kế hoạch là điều cần thiết để tạo\nra một cơ sở chăm sóc bệnh nhân an toàn và hỗ trợ.\n\nViệc lập kế hoạch hiệu quả đòi hỏi bệnh viện phải nhận thức được tất cả các rủi ro hiện có trong cơ sở. Mục tiêu là ngăn\nngừa tai nạn và thương tích và duy trì các điều kiện an toàn và bảo mật cho bệnh nhân, nhân viên và những người khác,\nchẳng hạn như gia đình, nhà thầu, nhà cung cấp, tình nguyện viên, khách đến thăm, học viên và sinh viên. Bệnh viện xây\ndựng và triển khai một chương trình an toàn bằng văn bản. Là một phần của chương trình an toàn, bệnh viện tiến hành và\nlập hồ sơ kiểm tra liên tục các cơ sở vật chất của mình. Kết quả của cuộc kiểm tra được xem xét và giải quyết trong một\nđánh giá rủi ro toàn diện, toàn bộ cơ sở được lập thành văn bản, ít nhất là hàng năm, để xác định các khu vực có rủi ro về\nan toàn và khả năng gây hại.\n\nPhân tích tại nơi làm việc, được tiến hành hàng năm để đánh giá mức độ an toàn của chương trình phòng ngừa bạo lực tại\nnơi làm việc của bệnh viện, bao gồm phân tích chủ động về nơi làm việc, điều tra các sự cố bạo lực tại nơi làm việc của\nbệnh viện và phân tích cách các chính sách và quy trình, đào tạo, giáo dục và thiết kế môi trường của chương trình phản\nánh các thông lệ tốt nhất và tuân thủ luật pháp và quy định hiện hành. Tất cả các sự cố và vấn đề về an toàn có thể được\nbáo cáo cho nhân viên đánh giá chất lượng, cải tiến hoặc các chức năng khác cũng như cho người đứng đầu được chỉ định\ncủa nỗ lực giảm bạo lực tại nơi làm việc. Tóm tắt các sự cố như vậy cũng có thể được chia sẻ với người được chỉ định để\nđiều phối các hoạt động quản lý an toàn. Việc xem xét các báo cáo sự cố thường yêu cầu phải tuân theo các quy trình pháp\nlý để bảo vệ tính bảo mật. Các cơ hội cải thiện việc chăm sóc, điều trị hoặc dịch vụ, hoặc ngăn ngừa các sự cố tương tự,\nkhông bị mất do tuân theo quy trình pháp lý.\n\nĐánh giá rủi ro cũng xem xét việc xem xét các quy trình và đánh giá các dịch vụ mới và đã lên kế hoạch có thể gây ra rủi\nro về an toàn. Điều quan trọng là phải có sự tham gia của một nhóm đa ngành khi tiến hành kiểm tra an toàn trong bệnh\nviện. Ví dụ về các rủi ro an toàn có khả năng gây thương tích hoặc gây hại bao gồm đồ đạc sắc nhọn và bị hỏng, cửa sổ bị\nvỡ, nước rò rỉ trên trần nhà, rủi ro về mặt công thái học (ví dụ: rủi ro cho nhân viên khi di chuyển bệnh nhân hoặc vật\nnặng) và rủi ro té ngã (ví dụ: do sàn không bằng phẳng hoặc trơn trượt hoặc thiếu lan can).\n\nViệc tiến hành kiểm tra thường xuyên để phát hiện rủi ro an toàn và đánh giá rủi ro an toàn hàng năm giúp bệnh viện xác\nđịnh, ưu tiên, lập kế hoạch và thực hiện các cải tiến. Việc ưu tiên và lập kế hoạch cũng bao gồm lập ngân sách cho việc\nnâng cấp hoặc thay thế cơ sở, hệ thống và thiết bị dài hạn.\n\nCác yếu tố đo lường được của FMS.03.00\n1.\nD Bệnh viện xây dựng và triển khai chương trình bằng văn bản để cung cấp cơ sở vật chất an toàn. (Xem thêm\nCOP.05.00, ME 1; GLD.07.02, ME 2; HCT.02.00, ME 1; PCI.01.01, ME 2)\n2.\nD Bệnh viện có biên bản kiểm tra an toàn cơ sở vật chất hiện hành, chính xác và được lập thành văn bản. Kết quả\nkiểm tra cơ sở vật chất được xem xét và giải quyết trong đánh giá rủi ro toàn diện cho toàn cơ sở. (Xem thêm\nFMS.02.00, ME 1)\n3.\nD Bệnh viện xác định mục tiêu, triển khai cải tiến và theo dõi dữ liệu để đảm bảo giảm thiểu hoặc loại bỏ các rủi ro\nan toàn liên quan đến bạo lực tại nơi làm việc. (Xem thêm GLD.07.02, ME 3)\n4.\nDựa trên quy trình của mình, bệnh viện báo cáo và điều tra các sự cố an toàn liên quan đến bệnh nhân, nhân viên\nhoặc những người khác trong cơ sở của mình.\n5.\nDựa trên quy trình của mình, bệnh viện báo cáo và điều tra các sự cố an toàn liên quan đến bạo lực tại nơi làm việc\nliên quan đến bệnh nhân, nhân viên hoặc những người khác trong cơ sở của mình. (Xem thêm GLD.07.02, ME 3)\n\nAn ninh","m":[],"sec":"An toàn"},{"c":"FMS.04.00","ch":"FMS","t":"Bệnh viện triển khai chương trình nhằm cung cấp môi trường an toàn cho bệnh nhân, gia đình, nhân viên và khách thăm.","p":"An ninh có nghĩa là bảo vệ tài sản của tổ chức và bệnh nhân, gia đình, khách thăm và nhân viên khỏi bị tổn hại hoặc mất mát.\nVí dụ về các lỗ hổng và mối đe dọa liên quan đến rủi ro an ninh bao gồm bạo lực tại nơi làm việc, bắt cóc trẻ sơ sinh, trộm cắp\nvà quyền truy cập không khóa/không an toàn vào các khu vực hạn chế trong bệnh viện. Các sự cố an ninh có thể do cá nhân\ntừ bên ngoài hoặc bên trong bệnh viện gây ra.\n\nBệnh viện xây dựng và triển khai chương trình an ninh bằng văn bản để đảm bảo mọi người trong bệnh viện được bảo vệ khỏi\nbị tổn hại về mặt cá nhân và mất mát hoặc thiệt hại tài sản. Điều này có thể bao gồm sự phối hợp với cơ quan thực thi pháp\nluật địa phương. Là một phần của chương trình an ninh, bệnh viện tiến hành và lập hồ sơ đánh giá rủi ro, ít nhất là hàng năm,\nđể xác định các khu vực có rủi ro an ninh. Đánh giá rủi ro cũng xem xét việc xem xét các quy trình và đánh giá các dịch vụ\nmới và đã lên kế hoạch có thể gây ra rủi ro an ninh.\n\nNhân viên, sinh viên, thực tập sinh, nhân viên hợp đồng, tình nguyện viên, nhà cung cấp, cá nhân liên kết với các đơn vị kinh\ndoanh độc lập và những người khác, theo quy định của bệnh viện, được xác định bằng phù hiệu (tạm thời hoặc vĩnh viễn)\nhoặc một hình thức nhận dạng khác. Những người khác, chẳng hạn như gia đình và khách thăm trong bệnh viện, có thể được\nxác định tùy thuộc vào chính sách, luật pháp và quy định của bệnh viện.\n\nCác khu vực hạn chế như hiệu thuốc, phòng trẻ sơ sinh và phòng phẫu thuật phải được bảo vệ và giám sát. Trẻ em, người lớn\ntuổi và bệnh nhân dễ bị tổn thương không có khả năng tự bảo vệ hoặc ra hiệu cầu cứu phải được bảo vệ khỏi nguy hiểm.\nNgoài ra, các khu vực xa xôi hoặc biệt lập của cơ sở và khuôn viên có thể yêu cầu sử dụng camera an ninh.\n\nCác yếu tố đo lường được của FMS.04.00\n1.\nBệnh viện xây dựng và triển khai một chương trình bằng văn bản để cung cấp một môi trường an toàn.\n2.\nChương trình an ninh xác định tất cả các khu vực rủi ro an ninh và khu vực hạn chế và đảm bảo rằng chúng\nđược giám sát và giữ an toàn. (Xem thêm COP.05.00, ME 1; MMU.03.00, ME 6; MMU.03.01, ME 2;\nPCC.01.03, ME 1)\n3.\nChương trình an ninh đảm bảo rằng bệnh nhân có liên quan, cũng như nhân viên, sinh viên, thực tập sinh,\nnhân viên hợp đồng, tình nguyện viên, nhà cung cấp và cá nhân liên kết với các thực thể kinh doanh độc lập,\nđược xác định.\n4.\nTất cả các thiết bị và hệ thống an ninh, bao gồm các thiết bị liên quan đến phát hiện, thông báo báo động và\nphản ứng kịp thời, đều được kiểm tra, đánh giá và bảo trì.\n5.\nChương trình an ninh bao gồm giáo dục nhân viên có liên quan về vai trò và trách nhiệm trong một sự kiện liên\nquan đến an ninh.\n6.\nBệnh viện tiến hành các cuộc tập trận thường xuyên với nhân viên để đánh giá chương trình an ninh và tích\nhợp với những người ứng phó tại địa phương.\n7.\nBệnh viện tiến hành phân tích nơi làm việc hàng năm liên quan đến chương trình phòng ngừa bạo lực tại nơi\nlàm việc và thực hiện các hành động để giảm thiểu hoặc giải quyết các rủi ro an ninh bạo lực tại nơi làm việc đã\nxác định. (Xem thêm GLD.07.02, ME 2)\n8.\nDựa trên quy trình của mình, bệnh viện báo cáo và điều tra các sự cố an ninh liên quan đến bệnh nhân, nhân\nviên hoặc những người khác trong cơ sở của mình.\n9. Dựa trên quy trình của mình, bệnh viện báo cáo và điều tra các sự cố an ninh liên quan đến bạo lực tại nơi làm\nviệc liên quan đến bệnh nhân, nhân viên hoặc những người khác trong cơ sở của mình. (Xem thêm GLD.07.02,\nME 3)\n\nVật liệu và chất thải nguy hại","m":[],"sec":"An ninh"},{"c":"FMS.05.00","ch":"FMS","t":"Bệnh viện triển khai chương trình quản lý vật liệu nguy hại và chất thải.","p":"Bệnh viện sử dụng nhiều loại vật liệu và chất thải nguy hại. Khi nhân viên được đào tạo về cách xử lý, lưu trữ và thải bỏ an\ntoàn các vật liệu và chất thải nguy hại, họ có nhiều khả năng tuân theo quy trình duy trì môi trường an toàn cho bệnh nhân,\nnhân viên và khách đến thăm. Do đó, điều quan trọng đối với bệnh viện là phải xây dựng và triển khai chương trình bằng văn\nbản để quản lý các vật liệu và chất thải nguy hại, bao gồm việc xác định và kiểm soát an toàn các vật liệu và chất thải này trong\ntoàn bộ cơ sở.\n\nBệnh viện xác định và lập danh mục các vật liệu nguy hại. Bệnh viện bắt đầu bằng cách tìm kiếm kỹ lưỡng tất cả các khu vực\ntrong tổ chức nơi có thể có vật liệu nguy hại.\nTài liệu từ cuộc tìm kiếm này phải bao gồm thông tin về loại từng vật liệu nguy hại được lưu trữ, số lượng vật liệu và địa\nđiểm trong tổ chức. Tài liệu này cũng phải đề cập đến số lượng tối đa được phép lưu trữ vật liệu nguy hại tại một địa\nđiểm/khu vực. Ví dụ, nếu vật liệu dễ cháy hoặc độc hại, thì sẽ có giới hạn về số lượng vật liệu có thể được lưu trữ tại một địa\nđiểm. Danh mục các vật liệu nguy hại được lập và cập nhật, ít nhất là hàng năm, để phản ánh những thay đổi về vật liệu nguy\nhại được sử dụng và lưu trữ trong tổ chức.\n\nVật liệu nguy hiểm có thể được phân loại theo các mục sau:\n•\nHóa chất (ví dụ: hóa chất dùng để vệ sinh, khử trùng, tiệt trùng, xử lý nước, bệnh lý, dược phẩm, vệ sinh tay)\n•\nThuốc gây độc tế bào và nguy hiểm\n•\nVật liệu phóng xạ\n•\nKhí và hơi nguy hiểm\n\nBệnh viện cũng thiết lập các loại chất thải nguy hại do tổ chức tạo ra và cách nhận dạng chúng (ví dụ: túi/thùng đựng chất thải\nđược mã hóa màu và dán nhãn). Sau đây là các loại chất thải nguy hại:\n•\nChất lây nhiễm\n•\nVật sắc nhọn\n•\nBệnh lý và giải phẫu\n•\nDược phẩm\n•\nHóa chất/kim loại nặng/thùng chứa chịu áp suất\n•\nĐộc gen/độc tế bào\n•\nVật liệu phóng xạ\n\nChương trình chất thải và vật liệu nguy hại của bệnh viện tuân thủ mọi luật và quy định hiện hành cũng như các tiêu chuẩn\nquốc gia, đồng thời giải quyết các vật liệu nguy hại và chất thải nguy hại bằng cách bao gồm các quy trình sau:\n•\nKiểm kê vật liệu và chất thải nguy hại, bao gồm loại, địa điểm và số lượng (ví dụ: gần đúng hoặc trung bình tại mỗi địa\nđiểm)\n•\nCập nhật số lượng tối đa được phép cho mỗi địa điểm ít nhất một lần một năm\n•\nXử lý, lưu trữ và sử dụng vật liệu nguy hại một cách an toàn\n•\nGhi nhãn vật liệu nguy hại một cách chính xác và rõ ràng, phù hợp với thông tin từ các\n•\nbảng dữ liệu an toàn (SDS)\n•\nThiết lập và xác định các loại chất thải nguy hại\n•\nXử lý và lưu trữ chất thải nguy hại một cách an toàn\n\n•\nTheo dõi số lượng và xử lý đúng cách chất thải nguy hại theo luật pháp và quy định của địa phương\n•\nSử dụng thiết bị và quy trình bảo vệ thích hợp cho các sự cố tràn và phơi nhiễm\n•\nBáo cáo và điều tra các sự cố tràn, phơi nhiễm và các sự cố khác\n•\nGhi lại giấy phép, giấy chứng nhận hoặc các yêu cầu theo quy định khác\n\nThông tin liên quan đến quy trình xử lý hoặc làm việc với vật liệu và chất thải nguy hại theo cách an toàn\nphải luôn có sẵn ngay lập tức và bao gồm thông tin về dữ liệu vật lý của vật liệu (chẳng hạn như điểm sôi,\nđiểm chớp cháy, v.v.), độc tính của vật liệu, tác động của việc sử dụng vật liệu nguy hại đối với sức khỏe,\nxác định cách bảo quản và xử lý đúng cách sau khi sử dụng, loại thiết bị bảo vệ cần thiết trong quá trình sử\ndụng và quy trình xử lý sự cố tràn, bao gồm sơ cứu bắt buộc đối với mọi loại phơi nhiễm. Nhiều nhà sản\nxuất cung cấp thông tin này dưới dạng SDS.\n\nTrong trường hợp xảy ra sự cố tràn vật liệu nguy hại, bệnh viện có các quy trình để ứng phó và xử lý sự\ncố tràn và phơi nhiễm. Các quy trình bao gồm việc chuẩn bị sẵn bộ dụng cụ xử lý sự cố tràn khi cần thiết\ncùng với thiết bị bảo vệ cá nhân phù hợp và vật liệu kiểm soát sự cố tràn cho loại và quy mô sự cố tràn\ntiềm ẩn. Các quy trình cũng đề cập đến cách báo cáo sự cố tràn và phơi nhiễm.\n\nBệnh viện triển khai các quy trình ứng phó với sự cố phơi nhiễm vật liệu nguy hiểm, bao gồm sơ cứu ban\nđầu, chăm sóc y tế phù hợp, báo cáo sự cố, v.v. Việc phơi nhiễm vật liệu nguy hiểm đòi hỏi phải được\ntiếp cận ngay với dịch vụ sơ cứu phù hợp. Trong một số trường hợp, chẳng hạn như khi tiếp xúc với hóa\nchất ăn mòn hoặc có tính ăn mòn, có thể cần phải tiếp cận trạm rửa mắt hoặc vòi hoa sen để xả nước\nngay lập tức và liên tục nhằm ngăn ngừa hoặc giảm thiểu thương tích. Trạm rửa mắt được thiết kế để xả\ncả hai mắt cùng lúc trong 15 phút liên tục với lưu lượng 1,5 lít mỗi phút (0,4 gallon mỗi phút). Tuy nhiên,\nkhông phải mọi trường hợp phơi nhiễm vật liệu nguy hiểm đều cần có trạm rửa mắt. Bệnh viện nên tiến\nhành đánh giá rủi ro để xác định nơi nào trong tổ chức cần có trạm rửa mắt, có tính đến các đặc tính vật lý\ncủa hóa chất nguy hiểm được sử dụng, cách nhân viên sử dụng các hóa chất này để thực hiện các hoạt\nđộng công việc của họ và cách nhân viên sử dụng thiết bị bảo vệ cá nhân. Các phương án thay thế cho\ntrạm rửa mắt có thể phù hợp tùy thuộc vào loại rủi ro và khả năng phơi nhiễm. Ví dụ, bình rửa mắt cá\nnhân có thể phù hợp ở những khu vực có nguy cơ tiếp xúc với chất gây kích ứng nhẹ hoặc nơi mọi người\ncó thể sử dụng bình để rửa ngay lập tức khi họ đi đến trạm rửa mắt phù hợp hoặc đến khu vực cần được\nchăm sóc y tế. Các bệnh viện lắp đặt trạm rửa mắt hoặc vòi hoa sen phải đảm bảo bảo trì đúng cách, bao\ngồm rửa hàng tuần và bảo trì phòng ngừa hàng năm.\n\nCác yếu tố đo lường được của FMS.05.00\n1.\nBệnh viện xây dựng và triển khai một chương trình bằng văn bản để quản lý vật liệu nguy hại và\nchất thải. (Xem thêm HRP.02.01, ME 2)\n2.\nChương trình vật liệu nguy hại và chất thải xác định loại, số lượng và vị trí của vật liệu nguy hại và\nchất thải, và có một bản kiểm kê đầy đủ, được cập nhật ít nhất hàng năm, để phản ánh những\nthay đổi về vật liệu nguy hại được sử dụng và lưu trữ trong tổ chức. (Xem thêm AOP.03.05, ME 1\nvà 5; MMU.03.00, ME 2; PCI.05.00, ME 1)\n3.\nChương trình vật liệu nguy hại và chất thải thiết lập và triển khai các quy trình dán nhãn rõ ràng,\nxử lý an toàn, lưu trữ và sử dụng vật liệu nguy hại phù hợp với các bảng dữ liệu an toàn.\n4.\nChương trình vật liệu nguy hại và chất thải thiết lập và triển khai các thiết bị bảo vệ phù hợp cần\nthiết trong quá trình xử lý và sử dụng vật liệu nguy hại.\n5.\nChương trình vật liệu nguy hại và chất thải thiết lập và thực hiện các quy trình để quản lý sự cố\ntràn và phơi nhiễm, bao gồm việc sử dụng thiết bị bảo vệ phù hợp và báo cáo sự cố tràn và phơi\nnhiễm.\n6.\nThông tin về vật liệu nguy hại liên quan đến việc xử lý an toàn, quy trình xử lý sự cố tràn và quy\ntrình quản lý phơi nhiễm luôn được cập nhật và có sẵn mọi lúc.\n7. Nhân viên có thể mô tả và/hoặc trình bày các biện pháp phòng ngừa và quy trình để xử lý và quản\nlý vật liệu nguy hại và chất thải, tùy theo vai trò và trách nhiệm của nhân viên.\n\nAn toàn phòng cháy chữa cháy","m":[],"sec":"Vật liệu và chất thải nguy hại"},{"c":"FMS.06.00","ch":"FMS","t":"Bệnh viện thiết lập và thực hiện chương trình an toàn phòng cháy chữa cháy tuân thủ các quy định, luật pháp và quy định của quốc gia và địa phương.","p":"Bệnh viện phải cảnh giác về an toàn phòng cháy chữa cháy vì hỏa hoạn là một rủi ro luôn hiện hữu trong môi trường\nchăm sóc sức khỏe. Để bảo vệ tất cả những người cư trú tại các cơ sở của bệnh viện khỏi hỏa hoạn và khói, bệnh viện\nxây dựng và triển khai một chương trình bằng văn bản về an toàn phòng cháy chữa cháy.\n\nĐánh giá liên tục về việc tuân thủ các quy định, luật lệ và quy định của quốc gia liên quan đến an toàn phòng cháy chữa\ncháy là rất quan trọng để xác định và giảm thiểu rủi ro.\n\nCó thể cần áp dụng một hoặc nhiều biện pháp tạm thời khi không thể triển khai ngay việc cải thiện theo kế hoạch để giải\nquyết rủi ro an toàn phòng cháy chữa cháy. Mục đích của việc triển khai các biện pháp tạm thời là để đảm bảo an toàn cho\nnhững người cư trú trong tòa nhà trong thời gian các tính năng và hệ thống an toàn phòng cháy chữa cháy bị lỗi, bị xâm\nphạm hoặc không hoạt động do xây dựng, bảo trì hoặc hỏng hóc hoặc sửa chữa. Loại và nhu cầu áp dụng một hoặc nhiều\nbiện pháp tạm thời sẽ phụ thuộc vào loại và phạm vi rủi ro an toàn phòng cháy chữa cháy và thời gian cho đến khi cải\nthiện theo kế hoạch để giải quyết hoàn toàn rủi ro được triển khai.\n\nChương trình an toàn phòng cháy chữa cháy bao gồm các tiêu chí để đánh giá thời điểm và mức độ cần triển khai các biện\npháp tạm thời.\n\nVí dụ về các biện pháp tạm thời bao gồm việc đăng biển báo để xác định lối thoát thay thế; kiểm tra lối ra/lối thoát hiểm\nhàng ngày tại khu vực bị ảnh hưởng; cung cấp hệ thống báo cháy và phát hiện cháy tạm thời nhưng tương đương khi hệ\nthống bị hỏng; cung cấp thêm thiết bị chữa cháy; tăng cường giám sát an toàn cháy nổ tại các tòa nhà, mặt bằng và thiết bị;\nvà cung cấp thêm đào tạo cho nhân viên về cách sử dụng thiết bị chữa cháy; trong số các biện pháp tạm thời khác.\n\nBệnh viện xem xét rủi ro đối với bệnh nhân, nhân viên và những người khác khi xác định kế hoạch và khung thời gian để\nthực hiện các cải tiến và/hoặc biện pháp tạm thời. Đánh giá rủi ro đang diễn ra và khung thời gian để thực hiện các biện\npháp và cải tiến tạm thời được ghi lại.\n\nLưu ý: Danh sách các biện pháp tạm thời bổ sung có thể được tìm thấy trong phần phụ lục “Biện pháp tạm thời” trong\nhướng dẫn này.\n\nCác yếu tố đo lường được của FMS.06.00\n1. Bệnh viện xây dựng và triển khai một chương trình bằng văn bản về an toàn phòng cháy chữa cháy để bảo\nvệ tất cả những người cư trú tại các cơ sở của bệnh viện khỏi các trường hợp khẩn cấp về hỏa hoạn và\nkhói.\n2. Chương trình an toàn phòng cháy chữa cháy bao gồm việc triển khai các biện pháp tạm thời, khi cần thiết, để\nđảm bảo rằng sự an toàn của bệnh nhân, nhân viên và khách đến thăm bệnh viện được duy trì khi không thể\ngiải quyết ngay các rủi ro về an toàn phòng cháy chữa cháy.\n3.  Đánh giá rủi ro toàn diện của bệnh viện trên toàn cơ sở theo yêu cầu của FMS.02.00, ME 1 bao gồm đánh giá\ncác rủi ro liên quan đến hỏa hoạn sau:\n•\nPhân cách hỏa hoạn\n•\nPhân cách/ngăn khói\n•\nCác khu vực nguy hiểm (và không gian phía trên trần nhà trong các khu vực đó) như phòng vải bẩn,\nphòng thu gom rác và phòng lưu trữ khí y tế\n•\nLối thoát hiểm\n•\nNhà bếp và các thiết bị nấu ăn tạo ra mỡ trong bếp\n•\nMáng giặt và máng rác\n•\nHệ thống và thiết bị điện khẩn cấp\n•\nCác thành phần của hệ thống khí y tế và chân không\n•\nLưu trữ và xử lý các vật liệu có khả năng dễ cháy (ví dụ: chất lỏng dễ cháy,\n•\nkhí dễ cháy, khí y tế oxy hóa như oxy và nitơ oxit)\n•\nCác quy trình và biện pháp phòng ngừa để ngăn ngừa và quản lý hỏa hoạn phẫu thuật\n•\nNguy cơ hỏa hoạn liên quan đến các dự án xây dựng, cải tạo hoặc phá dỡ","m":[],"sec":"An toàn phòng cháy chữa cháy"},{"c":"FMS.06.01","ch":"FMS","t":"Bệnh viện duy trì các thiết bị an toàn phòng cháy chữa cháy và các tính năng của tòa nhà an toàn phòng cháy chữa cháy.","p":"Mỗi bệnh viện cần lập kế hoạch về cách thức đảm bảo an toàn cho người dân trong trường hợp khẩn cấp về\nhỏa hoạn và khói. Cấu trúc và thiết kế của cơ sở chăm sóc sức khỏe có thể giúp ngăn ngừa, phát hiện và dập tắt\nhỏa hoạn, đồng thời cung cấp lối thoát an toàn khỏi cơ sở. Bệnh viện sẽ chuẩn bị tốt hơn cho các trường hợp\nkhẩn cấp về hỏa hoạn khi chương trình an toàn phòng cháy chữa cháy bao gồm phát hiện sớm, dập tắt và ngăn\nchặn hỏa hoạn và khói, cũng như các biện pháp đảm bảo thoát hiểm an toàn khỏi cơ sở khi xảy ra các trường\nhợp khẩn cấp về hỏa hoạn và khói.\nChương trình an toàn phòng cháy chữa cháy của bệnh viện giải quyết các vấn đề sau:\n•\nHệ thống cảnh báo sớm, phát hiện sớm và thông báo, chẳng hạn như máy dò khói, báo cháy và tuần tra\nphòng cháy chữa cháy\n•\nCơ chế dập lửa phù hợp với khu vực (ví dụ: phòng công nghệ thông tin, phòng điện) và loại hỏa hoạn có\nthể xảy ra, chẳng hạn như vòi nước, bình chữa cháy,\n•\nhệ thống dập lửa bằng hóa chất và hệ thống phun nước\n•\nNgăn chặn hỏa hoạn và khói, bao gồm các ngăn cách hỏa hoạn và ngăn khói, khi luật pháp và quy định của\nđịa phương yêu cầu; các tính năng ngăn chặn hỏa hoạn và khói được duy trì để đảm bảo\n•\nhiệu quả của chúng.\n•\nLối thoát hiểm an toàn và thông thoáng trong trường hợp khẩn cấp do hỏa hoạn hoặc khói, bao gồm biển\nbáo lối thoát hiểm rõ ràng mà những người trong bệnh viện có thể hiểu được (ví dụ, có biểu tượng và/hoặc\nngôn ngữ mà phần lớn những người trong bệnh viện hiểu được) và đèn chiếu sáng khẩn cấp\nCác tính năng như thế này giúp bệnh nhân, nhân viên và khách đến thăm có đủ thời gian để thoát khỏi cơ sở\nmột cách an toàn hoặc đến một địa điểm an toàn trong cơ sở trong trường hợp khẩn cấp do hỏa hoạn hoặc khói.\nCác tính năng này có hiệu quả bất kể tuổi đời, quy mô hoặc kết cấu của cơ sở.\n\nCác yếu tố đo lường được của FMS.06.01\n1. Chương trình an toàn phòng cháy chữa cháy bao gồm các thiết bị/hệ thống để phát hiện sớm và báo động khi có\ncháy và khói.\n2. Chương trình an toàn phòng cháy chữa cháy bao gồm các thiết bị/hệ thống để dập tắt cháy.\n3. Chương trình an toàn phòng cháy chữa cháy bao gồm lối thoát an toàn khỏi cơ sở thông qua lối ra thoát thông\nthoáng và không bị cản trở.\n4. Chương trình an toàn phòng cháy chữa cháy bao gồm biển báo lối thoát dễ thấy, dễ hiểu đối với những người\ntrong bệnh viện.\n5. Chương trình an toàn phòng cháy chữa cháy bao gồm đèn chiếu sáng cho hành lang thoát hiểm và cầu thang.\n6. Khi luật pháp và quy định của địa phương yêu cầu, chương trình an toàn phòng cháy chữa cháy bao gồm việc\nngăn chặn lửa và khói, và các tính năng này được duy trì để đảm bảo hiệu quả và an toàn.","m":[],"sec":"An toàn phòng cháy chữa cháy"},{"c":"FMS.06.02","ch":"FMS","t":"Tất cả các thiết bị và hệ thống an toàn phòng cháy chữa cháy, bao gồm các thiết bị liên quan đến phát hiện sớm, thông báo báo động và dập tắt, đều được kiểm tra, đánh giá và bảo trì.","p":"Chương trình an toàn phòng cháy chữa cháy của bệnh viện xác định tần suất kiểm tra, thử nghiệm và bảo trì hệ\nthống phòng cháy chữa cháy và an toàn, phù hợp với các yêu cầu. Thiết bị và hệ thống an toàn phòng cháy chữa\ncháy trong bệnh viện bao gồm nhưng không giới hạn ở những điều sau:\n•\nMáy dò nhiệt và khói\n•\nBáo cháy\n•\nMáy bơm chữa cháy\n•\nHệ thống ống đứng\n•\nVòi phun nước\n•\nHệ thống chữa cháy\n•\nVòi cứu hỏa\n•\nBình chữa cháy xách tay\n•\nCửa chống cháy và cụm lắp ráp (bao gồm cửa trượt và cửa cuốn)\n•\nThiết bị tự động tắt cho hệ thống xử lý không khí\n•\nHệ thống quản lý khói tự động\n\nBệnh viện kiểm tra, đánh giá và bảo trì tất cả các thiết bị và hệ thống an toàn phòng cháy chữa cháy trong tòa nhà\ncủa mình, bao gồm thiết bị phát hiện sớm và dập tắt cháy và khói. Các hoạt động và tần suất kiểm tra, thử nghiệm\nvà bảo trì phù hợp với khuyến nghị của nhà sản xuất. Khi các quy định, luật và quy định của địa phương bao gồm\ncác yêu cầu về kiểm tra, thử nghiệm và bảo trì thiết bị và hệ thống an toàn phòng cháy chữa cháy, bệnh viện sẽ tuân\nthủ các yêu cầu nghiêm ngặt hơn, cho dù đó là khuyến nghị của nhà sản xuất hay các quy định, luật và quy định của\nđịa phương.\n\nBất kỳ khiếm khuyết nào được xác định, chẳng hạn như hệ thống và thiết bị bị suy yếu hoặc không hoạt động, đều\nđược khắc phục ngay lập tức. Khi không thể thực hiện ngay các biện pháp khắc phục, các biện pháp tạm thời được\nthực hiện để giảm nguy cơ hỏa hoạn và đảm bảo an toàn cho bệnh nhân, nhân viên và khách đến thăm cho đến khi\ncác khiếm khuyết có thể được khắc phục hoàn toàn. Kết quả của tất cả các cuộc kiểm tra, thử nghiệm và bảo trì\nđều được ghi lại, bao gồm các biện pháp khắc phục và biện pháp tạm thời được thực hiện.\n\nCác yếu tố đo lường được của FMS.06.02\n1.\nTất cả các thiết bị và hệ thống an toàn phòng cháy chữa cháy, bao gồm cả các thiết bị phát hiện và\ndập tắt khói và cháy, đều được kiểm tra, đánh giá và bảo trì theo khuyến nghị của nhà sản xuất\nhoặc theo yêu cầu của các quy định, luật lệ và quy định của địa phương, tùy theo yêu cầu nào\nnghiêm ngặt hơn.\n2.  Việc kiểm tra, thử nghiệm và bảo trì tất cả các thiết bị và hệ thống an toàn phòng cháy chữa cháy\nđều được ghi lại, bao gồm kết quả và hành động khắc phục.\n3. Bất kỳ khiếm khuyết nào được phát hiện trong thiết bị và hệ thống an toàn phòng cháy chữa cháy\nđều được khắc phục ngay lập tức hoặc các biện pháp tạm thời được thực hiện để giảm nguy cơ cháy nổ\ncho đến khi các khiếm khuyết có thể được khắc phục hoàn toàn.","m":[]},{"c":"FMS.06.03","ch":"FMS","t":"Bệnh viện tiến hành các cuộc tập trận thường xuyên với nhân viên để đánh giá chương trình an toàn phòng cháy chữa cháy.","p":"Chương trình an toàn phòng cháy chữa cháy của bệnh viện bao gồm nhưng không giới hạn ở những nội dung sau:\n• Kế hoạch báo cáo và ứng phó với tình huống khẩn cấp về hỏa hoạn\n• Kế hoạch sơ tán an toàn khỏi cơ sở trong trường hợp khẩn cấp về hỏa hoạn hoặc khói\n• Quy trình đánh giá tất cả các phần của chương trình an toàn phòng cháy chữa cháy trong mỗi giai đoạn 12 tháng\n• Trách nhiệm của các nhân viên khác nhau trong trường hợp khẩn cấp về hỏa hoạn\n• Giáo dục cần thiết cho nhân viên để bảo vệ và sơ tán bệnh nhân hiệu quả khi xảy ra tình huống khẩn cấp\n• Nhân viên tham gia ít nhất một cuộc diễn tập an toàn phòng cháy chữa cháy mỗi năm hoặc thường xuyên hơn khi\ntheo yêu cầu của luật pháp và quy định, tiêu chuẩn phòng cháy chữa cháy quốc gia hoặc các cơ quan chức năng khác\n\nCác cuộc diễn tập để đánh giá chương trình an toàn phòng cháy chữa cháy có thể được thực hiện theo nhiều cách\nnhưng luôn phải bao gồm một thành phần vật lý trong đó nhân viên phải phản ứng với báo động và thực hiện các\nhành động thích hợp trong quá trình diễn tập báo động cháy. Nhân viên được đào tạo về những việc cần làm, cách\nthoát hiểm và nơi tập trung (các “điểm tập trung”). Bệnh viện có thể chọn tiến hành các cuộc diễn tập sơ tán trong\nnhiều ca làm việc khác nhau, bao gồm cả ban đêm và cuối tuần. (Các bài tập sơ tán mô phỏng tại các khu vực như\nkhoa chăm sóc đặc biệt, phòng phẫu thuật hoặc trên các tầng cao của tòa nhà có thể cung cấp thêm thông tin chi tiết\nnhưng không bắt buộc.) Lưu ý: Các bài tập sơ tán để đánh giá chương trình an toàn phòng cháy không nên liên quan\ntrực tiếp đến bệnh nhân hoặc khách; tuy nhiên, bài tập phải đề cập đến cách nhân viên\nsẽ bảo vệ bệnh nhân và khách trong trường hợp khẩn cấp do hỏa hoạn. Điều quan trọng cần lưu ý là các khu vực có\nnguy cơ cao của bệnh viện được xác định trong đánh giá rủi ro, chẳng hạn như phòng phẫu thuật và khu vực điều\ntrị tăng áp và thiết bị, có thể có những rủi ro riêng biệt đòi hỏi các yếu tố bổ sung trong bài tập an toàn phòng cháy.\nTrong trường hợp này, bệnh viện nên tiến hành các bài tập dựa trên những rủi ro này, cũng như luật pháp và quy\nđịnh, yêu cầu của Bộ Y tế hoặc các cơ quan có thẩm quyền khác.\n\nMột ví dụ khác về bài tập đánh giá chương trình an toàn phòng cháy là chỉ định một \"cảnh sát phòng cháy\" cho mỗi\nđơn vị và yêu cầu họ ngẫu nhiên hỏi nhân viên về những gì họ sẽ làm nếu xảy ra hỏa hoạn tại đơn vị của họ. Nhân\nviên có thể được hỏi những câu hỏi cụ thể, chẳng hạn như, \"Van khóa oxy ở đâu? Nếu bạn phải khóa van oxy, bạn\nsẽ chăm sóc những bệnh nhân cần oxy như thế nào? Bình chữa cháy được đặt ở đâu trong đơn vị của bạn và bạn sẽ\nsử dụng bình chữa cháy như thế nào/trong trường hợp nào? Bạn báo cáo hỏa hoạn như thế nào? Bạn bảo vệ bệnh\nnhân như thế nào trong trường hợp hỏa hoạn? Nếu bạn cần sơ tán bệnh nhân theo chiều ngang hoặc chiều dọc, quy\ntrình của bạn là gì?” Nhân viên phải có khả năng trả lời đúng những câu hỏi này. Cảnh sát phòng cháy chữa cháy\nphải ghi lại hồ sơ của những người đã tham gia. Các ví dụ khác về bài tập bao gồm giảng dạy và kiểm tra trên máy\ntính hoặc bài kiểm tra viết để nhân viên làm liên quan đến chương trình an toàn phòng cháy chữa cháy.\n\nBất kể bài tập nào được chọn để đánh giá chương trình an toàn phòng cháy chữa cháy, nhân viên phải có hiểu biết\nvề chương trình và có khả năng mô tả cách đưa bệnh nhân đến nơi an toàn. Nhân viên không đạt sẽ được đào tạo\nlại và kiểm tra lại.\n\nCác yếu tố đo lường được của FMS.06.03\n1.\nTất cả nhân viên bệnh viện, bao gồm cả ca đêm và cuối tuần, đều được đào tạo về chương trình\nan toàn phòng cháy chữa cháy và tham gia các cuộc diễn tập để đánh giá chương trình an toàn\nphòng cháy chữa cháy ít nhất một lần một năm hoặc thường xuyên hơn khi luật pháp và quy định\nhoặc các cơ quan chức năng khác yêu cầu.\n2.  Nhân viên chăm sóc bệnh nhân có thể mô tả và trình bày cách đưa bệnh nhân đến nơi an toàn.\n3. Kết quả của các bài tập đánh giá chương trình an toàn phòng cháy chữa cháy được ghi lại và nhân viên\nkhông đạt sẽ được đào tạo lại và kiểm tra lại về chương trình an toàn phòng cháy chữa cháy.","m":[],"sec":"An toàn phòng cháy chữa cháy"},{"c":"FMS.06.04","ch":"FMS","t":"Chương trình an toàn phòng cháy chữa cháy bao gồm việc hạn chế nhân viên và bệnh nhân hút thuốc ở những khu vực không dành cho bệnh nhân được chỉ định trong cơ sở.","p":"Chương trình an toàn phòng cháy chữa cháy đề cập đến việc hạn chế hút thuốc và đáp ứng các tiêu chí sau:\n•\nÁp dụng cho tất cả bệnh nhân, gia đình, nhân viên và khách thăm.\n•\nLoại bỏ việc hút thuốc trong các cơ sở của bệnh viện hoặc hạn chế tối thiểu việc hút thuốc ở các khu vực không\nphải chăm sóc bệnh nhân được chỉ định có thông gió ra bên ngoài.\n•\nCấm hút thuốc ở tất cả các khu vực đang xây dựng hoặc cải tạo.\n\nHút thuốc bao gồm nhưng không giới hạn ở việc sử dụng thuốc lá, xì gà, tẩu, shisha, thuốc lá điện tử (bao gồm\nthuốc lá điện tử và thiết bị vaping) và các nguồn gây cháy khác để hút thuốc.\n\nChương trình an toàn phòng cháy chữa cháy đề cập đến việc hạn chế hút thuốc xác định bất kỳ trường hợp ngoại lệ\nnào liên quan đến bệnh nhân, chẳng hạn như lý do y tế hoặc tâm thần mà bệnh nhân có thể được phép hút thuốc và\nnhững cá nhân được phép cấp ngoại lệ như vậy. Khi có ngoại lệ, bệnh nhân sẽ hút thuốc ở khu vực không phải điều\ntrị được chỉ định, tránh xa những bệnh nhân khác.\n\nCác yếu tố đo lường được của FMS.06.04\n1. Chương trình an toàn phòng cháy chữa cháy đề cập đến việc loại bỏ hoặc hạn chế hút thuốc trong cơ sở bệnh viện.\n2. Chương trình áp dụng cho bệnh nhân, gia đình, khách thăm và nhân viên.\n3. Chương trình xác định ai có thể cấp ngoại lệ cho bệnh nhân hút thuốc và khi nào những ngoại lệ đó được áp dụng.\n\nThiết bị y tế","m":[],"sec":"An toàn phòng cháy chữa cháy"},{"c":"FMS.07.00","ch":"FMS","t":"Bệnh viện xây dựng và triển khai chương trình quản lý trang thiết bị y tế trong toàn đơn vị.","p":"Quản lý thiết bị y tế được thực hiện để đảm bảo rằng tất cả các thiết bị đều hoạt động bình thường và có\nthể sử dụng.\n\nChương trình quản lý thiết bị y tế bao gồm những nội dung sau:\n• Kiểm kê tất cả các thiết bị y tế\n• Kiểm tra thường xuyên\n• Kiểm tra theo yêu cầu sử dụng và yêu cầu của nhà sản xuất\n• Ghi chép kết quả\n\n• Thực hiện bảo trì phòng ngừa, sửa chữa đáng kể và xử lý khi cần thiết\n• Hoàn thành hồ sơ ghi chép về tất cả công việc sửa chữa\nLà một phần của chương trình thiết bị y tế, bệnh viện tiến hành và lập hồ sơ đánh giá rủi ro, ít nhất là\nhàng năm, để xác định các khu vực có rủi ro về thiết bị y tế.\n\nQuản lý thiết bị y tế được thực hiện bởi một hoặc nhiều cá nhân có trình độ dựa trên kinh nghiệm\nnền tảng, trình độ học vấn và đào tạo. Thiết bị y tế được các khoa trong toàn bệnh viện sử dụng (ví dụ:\nnhóm cơ sở vật chất, nhóm kỹ thuật sinh học, dịch vụ môi trường) và phải có quy trình quản lý thống\nnhất để duy trì một hệ thống tích hợp. Thử nghiệm và kiểm tra được thực hiện khi thiết bị còn mới và\nsau đó liên tục theo độ tuổi, cách sử dụng và hướng dẫn của nhà sản xuất. Các cuộc kiểm tra, kết quả\nthử nghiệm, bất kỳ hoạt động bảo trì và sửa chữa nào đều được lập hồ sơ để đảm bảo tính liên tục của\ncác quy trình và hướng dẫn lập kế hoạch vốn cho việc thay thế, nâng cấp và các thay đổi khác.\n\nCác yếu tố đo lường được của FMS.07.00\n1.\nBệnh viện xây dựng và triển khai chương trình bằng văn bản để quản lý thiết bị y tế thuộc sở hữu của bệnh\nviện và không thuộc sở hữu của bệnh viện (thuê, cho thuê, bệnh nhân sở hữu). (Xem thêm GLD.05.02, ME\n1; HRP.02.01, ME 2)\n2.\nChương trình thiết bị bao gồm các nội dung sau:\n•\nKiểm kê tất cả các thiết bị y tế\n•\nKiểm tra thường xuyên khi thiết bị mới và theo yêu cầu của hướng dẫn của nhà sản xuất\n•\nKiểm tra theo yêu cầu sử dụng và yêu cầu của nhà sản xuất\n•\nGhi chép kết quả\n•\nThực hiện bảo trì phòng ngừa và hiệu chuẩn khi áp dụng\n•\nTuân thủ luật pháp và quy định của địa phương\n•\n(Xem thêm AOP.03.04, ME 2; AOP.05.04, ME 2)\n1. Bệnh viện xác định mục tiêu, triển khai cải tiến và theo dõi dữ liệu để đảm bảo giảm thiểu hoặc loại bỏ rủi ro\nliên quan đến thiết bị y tế.","m":[],"sec":"Thiết bị y tế"}];})(window);
